  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { OpencodeConfig } from "./config-builder";
  3→import { buildOpencodeConfig } from "./config-builder";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types — exported for tests
 11→// ---------------------------------------------------------------------------
 12→
 13→export type OpenCodeHandle = {
 14→  sessionId: string;
 15→  abort: () => void;
 16→  sendPrompt: (text: string) => Promise<void>;
 17→  eventStream: AsyncIterable<unknown>;
 18→};
 19→
 20→export type SpawnOpenCodeFn = (
 21→  config: OpencodeConfig,
 22→  worktreePath: string,
 23→  taskId: string,
 24→) => Promise<OpenCodeHandle>;
 25→
 26→export type SessionDeps = {
 27→  surreal: Surreal;
 28→  shellExec: ShellExec;
 29→  brainBaseUrl: string;
 30→  spawnOpenCode?: SpawnOpenCodeFn;
 31→};
 32→
 33→export type SessionErrorCode =
 34→  | "TASK_NOT_FOUND"
 35→  | "TASK_NOT_ASSIGNABLE"
 36→  | "AGENT_ALREADY_ACTIVE"
 37→  | "WORKSPACE_MISMATCH"
 38→  | "MISSING_TASK_ID"
 39→  | "WORKTREE_ERROR"
 40→  | "SESSION_NOT_FOUND"
 41→  | "SESSION_ERROR";
 42→
 43→export type SessionError = {
 44→  code: SessionErrorCode;
 45→  message: string;
 46→  httpStatus: number;
 47→};
 48→
 49→export type SessionResult<T> =
 50→  | { ok: true; value: T }
 51→  | { ok: false; error: SessionError };
 52→
 53→export type OrchestratorSessionResult = SessionResult<{
 54→  agentSessionId: string;
 55→  streamId: string;
 56→  worktreeBranch: string;
 57→}>;
 58→
 59→export type SessionStatusResult = SessionResult<{
 60→  orchestratorStatus: OrchestratorStatus;
 61→  worktreeBranch?: string;
 62→  worktreePath?: string;
 63→  lastEventAt?: string;
 64→  startedAt?: string;
 65→  error?: string;
 66→}>;
 67→
 68→export type AbortSessionResult = SessionResult<{
 69→  aborted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type AcceptSessionResult = SessionResult<{
 74→  accepted: boolean;
 75→  sessionId: string;
 76→}>;
 77→
 78→export type ReviewResult = SessionResult<{
 79→  taskTitle: string;
 80→  diff: import("./worktree-manager").DiffResult;
 81→  session: {
 82→    orchestratorStatus: string;
 83→    worktreeBranch?: string;
 84→    startedAt?: string;
 85→    lastEventAt?: string;
 86→    toolCallCount?: number;
 87→    filesEdited?: number;
 88→  };
 89→}>;
 90→
 91→export type RejectSessionResult = SessionResult<{
 92→  rejected: boolean;
 93→  continuing: boolean;
 94→}>;
