308→// ---------------------------------------------------------------------------
309→// getOrchestratorSessionStatus
310→// ---------------------------------------------------------------------------
311→
312→type GetStatusInput = {
313→  surreal: Surreal;
314→  sessionId: string;
315→};
316→
317→export async function getOrchestratorSessionStatus(
318→  input: GetStatusInput,
319→): Promise<SessionStatusResult> {
320→  const lookup = await lookupSession(input.surreal, input.sessionId);
321→  if (!lookup.ok) {
322→    return { ok: false, error: lookup.error };
323→  }
324→  const { session } = lookup;
325→
326→  return {
327→    ok: true,
328→    value: {
329→      orchestratorStatus: lookup.status,
330→      ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
331→      ...(session.worktree_path ? { worktreePath: session.worktree_path } : {}),
332→      ...(session.started_at ? { startedAt: session.started_at } : {}),
333→      ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
334→      ...(session.error ? { error: session.error } : {}),
335→    },
336→  };
337→}
338→
339→// ---------------------------------------------------------------------------
340→// abortOrchestratorSession
341→// ---------------------------------------------------------------------------
342→
343→type AbortSessionInput = {
344→  surreal: Surreal;
345→  shellExec: ShellExec;
346→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
347→  sessionId: string;
348→  endAgentSession: (input: {
349→    surreal: Surreal;
350→    workspaceRecord: RecordId<"workspace", string>;
351→    sessionId: string;
352→    summary: string;
353→  }) => Promise<{ session_id: string; ended: boolean }>;
354→};
355→
356→export async function abortOrchestratorSession(
357→  input: AbortSessionInput,
358→): Promise<AbortSessionResult> {
359→  const lookup = await lookupSession(input.surreal, input.sessionId);
360→  if (!lookup.ok) {
361→    return { ok: false, error: lookup.error };
362→  }
363→  const { session, record: sessionRecord } = lookup;
364→
365→  // 1. Kill the OpenCode process if handle exists
366→  const handle = handleRegistry.get(input.sessionId);
367→  if (handle) {
368→    handle.abort();
369→    handleRegistry.delete(input.sessionId);
370→  }
371→
372→  // 2. Update orchestrator_status to aborted
373→  await input.surreal.update(sessionRecord).merge({
374→    orchestrator_status: "aborted" as OrchestratorStatus,
375→  });
376→
377→  // 3. Remove worktree if branch name exists
378→  if (session.worktree_branch && session.workspace) {
379→    const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
380→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
381→  }
382→
383→  // 4. Return task to ready
384→  if (session.task_id) {
385→    await input.surreal.update(session.task_id).merge({
386→      status: "ready",
387→      updated_at: new Date(),
388→    });
389→  }
390→
391→  // 5. End the agent session
392→  if (!session.workspace) {
393→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
394→  }
395→  await input.endAgentSession({
396→    surreal: input.surreal,
397→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
398→    sessionId: input.sessionId,
399→    summary: "Session aborted",
400→  });
401→
402→  return {
403→    ok: true,
404→    value: {
405→      aborted: true,
406→      sessionId: input.sessionId,
407→    },
408→  };
409→}
410→
411→// ---------------------------------------------------------------------------
412→// acceptOrchestratorSession
413→// ---------------------------------------------------------------------------
414→
415→type AcceptSessionInput = {
416→  surreal: Surreal;
417→  sessionId: string;
418→  summary: string;
419→  endAgentSession: (input: {
420→    surreal: Surreal;
421→    workspaceRecord: RecordId<"workspace", string>;
422→    sessionId: string;
423→    summary: string;
424→  }) => Promise<{ session_id: string; ended: boolean }>;
425→};
426→
427→export async function acceptOrchestratorSession(
428→  input: AcceptSessionInput,
429→): Promise<AcceptSessionResult> {
430→  const lookup = await lookupSession(input.surreal, input.sessionId);
431→  if (!lookup.ok) {
432→    return { ok: false, error: lookup.error };
433→  }
434→  const { session, record: sessionRecord, status } = lookup;
435→
436→  if (!ACCEPTABLE_STATUSES.has(status)) {
437→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
438→  }
439→
440→  // 1. Update orchestrator_status to completed
441→  await input.surreal.update(sessionRecord).merge({
442→    orchestrator_status: "completed" as OrchestratorStatus,
443→  });
444→
445→  // 2. Mark task as done
446→  if (session.task_id) {
447→    await input.surreal.update(session.task_id).merge({
448→      status: "done",
449→      updated_at: new Date(),
450→    });
451→  }
452→
453→  // 3. Clean up handle registry
454→  handleRegistry.delete(input.sessionId);
455→
456→  // 4. End the agent session
457→  if (!session.workspace) {
458→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
459→  }
460→  await input.endAgentSession({
461→    surreal: input.surreal,
462→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
463→    sessionId: input.sessionId,
464→    summary: input.summary,
465→  });
466→
467→  return {
468→    ok: true,
469→    value: {
470→      accepted: true,
471→      sessionId: input.sessionId,
472→    },
473→  };
474→}
475→
476→// ---------------------------------------------------------------------------
477→// State guard helpers
478→// ---------------------------------------------------------------------------
479→
480→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
481→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
482→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
483→
484→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
485→  return {
486→    code: "SESSION_ERROR",
487→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
488→    httpStatus: 409,
489→  };
490→}
491→
492→function sessionAborted(sessionId: string): SessionError {
493→  return {
494→    code: "SESSION_ERROR",
495→    message: `Session ${sessionId} has been aborted`,
496→    httpStatus: 409,
497→  };
498→}
