503→
504→type GetReviewInput = {
505→  surreal: Surreal;
506→  sessionId: string;
507→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
508→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
509→  getTaskTitle: (taskId: string) => Promise<string>;
510→};
511→
512→export async function getOrchestratorReview(
513→  input: GetReviewInput,
514→): Promise<ReviewResult> {
515→  const lookup = await lookupSession(input.surreal, input.sessionId);
516→  if (!lookup.ok) {
517→    return { ok: false, error: lookup.error };
518→  }
519→  const { session, status } = lookup;
520→
521→  if (status === "aborted") {
522→    return { ok: false, error: sessionAborted(input.sessionId) };
523→  }
524→
525→  if (!REVIEWABLE_STATUSES.has(status)) {
526→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
527→  }
528→
529→  // Get diff from the branch
530→  const branchName = session.worktree_branch ?? "";
531→  if (!session.workspace) {
532→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
533→  }
534→  const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
535→  const diffResult = await input.getDiff(repoRoot, branchName);
536→
537→  const diff = diffResult.ok
538→    ? diffResult.value
539→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
540→
541→  // Get task title
542→  const taskId = session.task_id ? (session.task_id.id as string) : "";
543→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
544→
545→  return {
546→    ok: true,
547→    value: {
548→      taskTitle,
549→      diff,
550→      session: {
551→        orchestratorStatus: status,
552→        ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
553→        ...(session.started_at ? { startedAt: session.started_at } : {}),
554→        ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
555→      },
556→    },
557→  };
558→}
