 42→// ---------------------------------------------------------------------------
 43→// Types
 44→// ---------------------------------------------------------------------------
 45→
 46→export type AgentStreamEvent = {
 47→  type: string;
 48→  sessionId?: string;
 49→  token?: string;
 50→  file?: string;
 51→  changeType?: string;
 52→  status?: string;
