 58→  entryType: "agent_text" | "file_change" | "user_prompt" | "status_change" | "stall_warning";
 59→  timestamp: string;
 60→  content?: string;
 61→  file?: string;
 62→  changeType?: string;
 63→  status?: string;
 64→};
 65→
 66→export type ConversationLogResponse = {
