139→async function lookupSession(
140→  surreal: Surreal,
141→  sessionId: string,
142→): Promise<SessionLookup> {
143→  const record = new RecordId("agent_session", sessionId);
144→  const session = await surreal.select<SessionRow>(record);
145→  if (!session) {
146→    return { ok: false, error: sessionNotFound(sessionId) };
147→  }
148→  if (!session.orchestrator_status) {
149→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
150→  }
151→  const status = session.orchestrator_status as OrchestratorStatus;
152→  return { ok: true, session, record, status };
153→}
