297→// Default spawn -- placeholder for production use
298→async function defaultSpawnOpenCode(
299→  _config: OpencodeConfig,
300→  _worktreePath: string,
301→  _taskId: string,
302→): Promise<OpenCodeHandle> {
303→  throw new Error(
304→    "spawnOpenCode not provided -- must be injected for production use",
305→  );
306→}
