143→// spawnOpenCode — production implementation
144→// ---------------------------------------------------------------------------
145→
146→export async function spawnOpenCode(
147→  config: OpencodeConfig,
148→  worktreePath: string,
149→  taskId: string,
150→): Promise<OpenCodeHandle> {
151→  const hostname = "127.0.0.1";
152→  const port = await findFreePort();
153→  const sdkConfig = toSdkConfig(config);
154→
155→  const abortController = new AbortController();
156→
157→  const { proc, url } = await startServerProcess(
158→    port,
159→    hostname,
160→    sdkConfig,
161→    worktreePath,
162→    abortController.signal,
163→  );
164→
165→  const client = createOpencodeClient({ baseUrl: url });
166→
167→  // 1. Create session
168→  const response = await client.session.create({
169→    body: { title: `Brain task: ${taskId}` },
170→  });
171→
172→  if (response.error) {
173→    abortController.abort();
174→    proc.kill();
175→    throw new Error(`Failed to create OpenCode session: ${JSON.stringify(response.error)}`);
176→  }
177→
178→  const sessionId = response.data.id;
179→
180→  // 2. Subscribe to event stream
181→  const events = await client.event.subscribe();
182→
183→  // 3. Send initial command: /brain-start-task <taskId>
184→  //    Triggers the brain CLI to load task context and validates
185→  //    CLI installation + authentication. Errors surface via events.
186→  client.session.command({
187→    path: { id: sessionId },
188→    body: { command: "brain-start-task", arguments: taskId },
189→  }).catch(() => {
190→    // Errors surface via the event stream as session.error events
191→  });
192→
193→  // 4. Build sendPrompt for follow-up messages
194→  const sendPrompt = async (text: string): Promise<void> => {
195→    await client.session.promptAsync({
196→      path: { id: sessionId },
197→      body: { parts: [{ type: "text", text }] },
198→    });
199→  };
200→
201→  return {
202→    sessionId,
203→    sendPrompt,
204→    eventStream: events.stream,
205→    abort: () => {
206→      try {
207→        client.session.abort({ path: { id: sessionId } }).catch(() => {});
208→      } finally {
209→        abortController.abort();
210→        proc.kill();
211→      }
212→    },
213→  };
214→}
