218→  | { ok: false; error: SessionError };
219→
220→async function lookupSession(
221→  surreal: Surreal,
222→  sessionId: string,
223→): Promise<SessionLookup> {
224→  const record = new RecordId("agent_session", sessionId);
225→  const session = await surreal.select<SessionRow>(record);
226→  if (!session) {
227→    return { ok: false, error: sessionNotFound(sessionId) };
228→  }
229→  if (!session.orchestrator_status) {
230→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
231→  }
232→  const status = session.orchestrator_status as OrchestratorStatus;
233→  return { ok: true, session, record, status };
