289→export async function createOrchestratorSession(
290→  input: CreateSessionInput,
291→): Promise<OrchestratorSessionResult> {
292→  // 1. Validate assignment eligibility
293→  const assignmentResult = await input.validateAssignment(
294→    input.surreal,
295→    input.workspaceId,
296→    input.taskId,
297→  );
298→
299→  if (!assignmentResult.ok) {
300→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
301→  }
302→
303→  const { validation } = assignmentResult;
304→  const taskSlug = slugFromTitle(validation.title);
305→  const repoRoot = validation.repoPath;
306→
307→  // 2. Create worktree
308→  const worktreeResult = await createWorktree(
309→    input.shellExec,
310→    repoRoot,
311→    taskSlug,
312→  );
313→
314→  if (!worktreeResult.ok) {
315→    return {
316→      ok: false,
317→      error: worktreeError(worktreeResult.error.message),
318→    };
319→  }
320→
321→  const { branchName, worktreePath } = worktreeResult.value;
322→
323→  // 3. Create agent_session record
324→  const { session_id: agentSessionId } = await input.createAgentSession({
325→    surreal: input.surreal,
326→    agent: "opencode",
327→    workspaceRecord: validation.workspaceRecord,
328→    taskId: input.taskId,
329→  });
330→
331→  const streamId = generateStreamId(agentSessionId);
332→
333→  // 4. Build config and spawn OpenCode
334→  const config = buildOpencodeConfig({
335→    brainBaseUrl: input.brainBaseUrl,
336→    workspaceId: input.workspaceId,
337→    authToken: input.authToken,
338→  });
339→
340→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
341→  let handle: OpenCodeHandle;
342→  try {
343→    handle = await spawnFn(config, worktreePath, input.taskId);
344→  } catch (err) {
345→    // Rollback: remove worktree and delete agent_session on spawn failure
346→    await removeWorktree(input.shellExec, repoRoot, branchName);
347→    const sessionRecord = new RecordId("agent_session", agentSessionId);
348→    await input.surreal.delete(sessionRecord);
349→    return {
350→      ok: false,
351→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
352→    };
353→  }
354→
355→  // 5. Register handle for later abort
356→  handleRegistry.set(agentSessionId, handle);
357→
358→  // 6. Update agent_session with orchestrator fields
359→  const sessionRecord = new RecordId("agent_session", agentSessionId);
360→  await input.surreal.update(sessionRecord).merge({
361→    orchestrator_status: "spawning" as OrchestratorStatus,
362→    worktree_branch: branchName,
363→    worktree_path: worktreePath,
364→    opencode_session_id: handle.sessionId,
365→    stream_id: streamId,
366→  });
367→
368→  return {
369→    ok: true,
370→    value: {
371→      agentSessionId,
372→      streamId,
373→      worktreeBranch: branchName,
374→    },
375→  };
376→}
