380→  _config: OpencodeConfig,
381→  _worktreePath: string,
382→  _taskId: string,
383→): Promise<OpenCodeHandle> {
384→  throw new Error(
385→    "spawnOpenCode not provided -- must be injected for production use",
386→  );
387→}
