398→export async function getOrchestratorSessionStatus(
399→  input: GetStatusInput,
400→): Promise<SessionStatusResult> {
401→  const lookup = await lookupSession(input.surreal, input.sessionId);
402→  if (!lookup.ok) {
403→    return { ok: false, error: lookup.error };
404→  }
405→  const { session } = lookup;
406→
407→  return {
408→    ok: true,
409→    value: {
410→      orchestratorStatus: lookup.status,
411→      ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
412→      ...(session.worktree_path ? { worktreePath: session.worktree_path } : {}),
413→      ...(session.started_at ? { startedAt: session.started_at } : {}),
414→      ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
415→      ...(session.error ? { error: session.error } : {}),
416→    },
417→  };
418→}
419→
420→// ---------------------------------------------------------------------------
421→// abortOrchestratorSession
422→// ---------------------------------------------------------------------------
423→
424→type AbortSessionInput = {
425→  surreal: Surreal;
426→  shellExec: ShellExec;
427→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
428→  sessionId: string;
429→  endAgentSession: (input: {
430→    surreal: Surreal;
431→    workspaceRecord: RecordId<"workspace", string>;
432→    sessionId: string;
433→    summary: string;
434→  }) => Promise<{ session_id: string; ended: boolean }>;
435→};
436→
437→export async function abortOrchestratorSession(
438→  input: AbortSessionInput,
439→): Promise<AbortSessionResult> {
440→  const lookup = await lookupSession(input.surreal, input.sessionId);
441→  if (!lookup.ok) {
442→    return { ok: false, error: lookup.error };
443→  }
444→  const { session, record: sessionRecord } = lookup;
445→
446→  // 1. Kill the OpenCode process if handle exists
447→  const handle = handleRegistry.get(input.sessionId);
448→  if (handle) {
449→    handle.abort();
450→    handleRegistry.delete(input.sessionId);
451→  }
452→
453→  // 2. Update orchestrator_status to aborted
454→  await input.surreal.update(sessionRecord).merge({
455→    orchestrator_status: "aborted" as OrchestratorStatus,
456→  });
457→
458→  // 3. Remove worktree if branch name exists
459→  if (session.worktree_branch && session.workspace) {
460→    const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
461→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
462→  }
463→
464→  // 4. Return task to ready
465→  if (session.task_id) {
466→    await input.surreal.update(session.task_id).merge({
467→      status: "ready",
468→      updated_at: new Date(),
469→    });
470→  }
471→
472→  // 5. End the agent session
473→  if (!session.workspace) {
474→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
475→  }
476→  await input.endAgentSession({
477→    surreal: input.surreal,
478→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
479→    sessionId: input.sessionId,
480→    summary: "Session aborted",
481→  });
482→
483→  return {
484→    ok: true,
485→    value: {
486→      aborted: true,
487→      sessionId: input.sessionId,
488→    },
489→  };
490→}
