493→// acceptOrchestratorSession
494→// ---------------------------------------------------------------------------
495→
496→type AcceptSessionInput = {
497→  surreal: Surreal;
498→  sessionId: string;
499→  summary: string;
500→  endAgentSession: (input: {
501→    surreal: Surreal;
502→    workspaceRecord: RecordId<"workspace", string>;
503→    sessionId: string;
504→    summary: string;
505→  }) => Promise<{ session_id: string; ended: boolean }>;
506→};
507→
508→export async function acceptOrchestratorSession(
509→  input: AcceptSessionInput,
510→): Promise<AcceptSessionResult> {
511→  const lookup = await lookupSession(input.surreal, input.sessionId);
512→  if (!lookup.ok) {
513→    return { ok: false, error: lookup.error };
514→  }
515→  const { session, record: sessionRecord, status } = lookup;
516→
517→  if (!ACCEPTABLE_STATUSES.has(status)) {
518→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
519→  }
520→
521→  // 1. Update orchestrator_status to completed
522→  await input.surreal.update(sessionRecord).merge({
523→    orchestrator_status: "completed" as OrchestratorStatus,
524→  });
525→
526→  // 2. Mark task as done
527→  if (session.task_id) {
528→    await input.surreal.update(session.task_id).merge({
529→      status: "done",
530→      updated_at: new Date(),
531→    });
532→  }
533→
534→  // 3. Clean up handle registry
535→  handleRegistry.delete(input.sessionId);
536→
537→  // 4. End the agent session
538→  if (!session.workspace) {
539→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
540→  }
541→  await input.endAgentSession({
542→    surreal: input.surreal,
543→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
544→    sessionId: input.sessionId,
545→    summary: input.summary,
546→  });
547→
548→  return {
549→    ok: true,
550→    value: {
551→      accepted: true,
552→      sessionId: input.sessionId,
553→    },
554→  };
555→}
