561→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
562→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
563→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
