565→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
566→  return {
567→    code: "SESSION_ERROR",
568→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
569→    httpStatus: 409,
570→  };
571→}
