582→// getOrchestratorReview
583→// ---------------------------------------------------------------------------
584→
585→type GetReviewInput = {
586→  surreal: Surreal;
587→  sessionId: string;
588→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
589→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
590→  getTaskTitle: (taskId: string) => Promise<string>;
591→};
592→
593→export async function getOrchestratorReview(
594→  input: GetReviewInput,
595→): Promise<ReviewResult> {
596→  const lookup = await lookupSession(input.surreal, input.sessionId);
597→  if (!lookup.ok) {
598→    return { ok: false, error: lookup.error };
599→  }
600→  const { session, status } = lookup;
601→
602→  if (status === "aborted") {
603→    return { ok: false, error: sessionAborted(input.sessionId) };
604→  }
605→
606→  if (!REVIEWABLE_STATUSES.has(status)) {
607→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
608→  }
609→
610→  // Get diff from the branch
611→  const branchName = session.worktree_branch ?? "";
612→  if (!session.workspace) {
613→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
614→  }
615→  const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
616→  const diffResult = await input.getDiff(repoRoot, branchName);
617→
618→  const diff = diffResult.ok
619→    ? diffResult.value
620→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
621→
622→  // Get task title
623→  const taskId = session.task_id ? (session.task_id.id as string) : "";
624→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
625→
626→  return {
627→    ok: true,
628→    value: {
629→      taskTitle,
630→      diff,
631→      session: {
632→        orchestratorStatus: status,
633→        ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
634→        ...(session.started_at ? { startedAt: session.started_at } : {}),
635→        ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
636→      },
637→    },
638→  };
639→}
