644→
645→type RejectSessionInput = {
646→  surreal: Surreal;
647→  sessionId: string;
648→  feedback: string;
649→};
650→
651→export async function rejectOrchestratorSession(
652→  input: RejectSessionInput,
653→): Promise<RejectSessionResult> {
654→  const lookup = await lookupSession(input.surreal, input.sessionId);
655→  if (!lookup.ok) {
656→    return { ok: false, error: lookup.error };
657→  }
658→  const { session, record: sessionRecord, status } = lookup;
659→
660→  if (!REJECTABLE_STATUSES.has(status)) {
661→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
662→  }
663→
664→  // 1. Update session status to active (agent resumes work)
665→  await input.surreal.update(sessionRecord).merge({
666→    orchestrator_status: "active" as OrchestratorStatus,
667→    last_feedback: input.feedback,
668→  });
669→
670→  // 2. Return task to in_progress
671→  if (session.task_id) {
672→    await input.surreal.update(session.task_id).merge({
673→      status: "in_progress",
674→      updated_at: new Date(),
675→    });
676→  }
677→
678→  return {
679→    ok: true,
680→    value: {
681→      rejected: true,
682→      continuing: true,
683→    },
684→  };
685→}
