 76→/**
 77→ * Subscribes to an agent session's SSE stream and collects events
 78→ * until a terminal event or timeout.
 79→ */
 80→export async function collectSessionEvents(
 81→  baseUrl: string,
 82→  streamUrl: string,
 83→  options: {
 84→    timeoutMs?: number;
 85→    stopOnTypes?: string[];
 86→    maxEvents?: number;
 87→  } = {},
 88→): Promise<AgentStreamEvent[]> {
 89→  const timeoutMs = options.timeoutMs ?? 15_000;
 90→  const stopOnTypes = options.stopOnTypes ?? ["agent_done", "agent_error"];
 91→  const maxEvents = options.maxEvents ?? 1000;
 92→
 93→  const response = await fetch(`${baseUrl}${streamUrl}`, {
 94→    headers: { Accept: "text/event-stream" },
 95→  });
 96→
 97→  if (!response.ok || !response.body) {
 98→    throw new Error(`Failed to open session event stream (${response.status})`);
 99→  }
100→
101→  const reader = response.body.getReader();
102→  const decoder = new TextDecoder();
103→  const events: AgentStreamEvent[] = [];
104→  let buffer = "";
105→
106→  const timeout = setTimeout(() => {
107→    void reader.cancel();
108→  }, timeoutMs);
109→
110→  try {
111→    while (true) {
112→      const { value, done } = await reader.read();
113→      if (done) break;
114→
115→      buffer += decoder.decode(value, { stream: true });
116→      const segments = buffer.split("\n\n");
117→      buffer = segments.pop() ?? "";
118→
119→      for (const segment of segments) {
120→        const dataLine = segment
121→          .split("\n")
122→          .find((line) => line.startsWith("data: "));
123→        if (!dataLine) continue;
124→
125→        const event = JSON.parse(
126→          dataLine.slice("data: ".length),
127→        ) as AgentStreamEvent;
128→        events.push(event);
129→
130→        if (stopOnTypes.includes(event.type) || events.length >= maxEvents) {
131→          return events;
132→        }
133→      }
134→    }
135→  } finally {
136→    clearTimeout(timeout);
137→    reader.releaseLock();
138→  }
139→
140→  return events;
141→}
