191→/**
192→ * Waits for a session to reach one of the target statuses.
193→ * Polls the session status endpoint at intervals.
194→ */
195→export async function waitForSessionStatus(
196→  baseUrl: string,
197→  user: TestUser,
198→  workspaceId: string,
199→  sessionId: string,
200→  targetStatuses: string[],
201→  options: { timeoutMs?: number; intervalMs?: number } = {},
202→): Promise<string> {
203→  const { getSessionStatus } = await import(
204→    "../coding-agent-orchestrator/orchestrator-test-kit"
205→  );
206→  const timeoutMs = options.timeoutMs ?? 30_000;
207→  const intervalMs = options.intervalMs ?? 500;
208→  const start = Date.now();
209→
210→  while (Date.now() - start < timeoutMs) {
211→    const status = await getSessionStatus(
212→      baseUrl,
213→      user,
214→      workspaceId,
215→      sessionId,
216→    );
217→    if (targetStatuses.includes(status.orchestratorStatus)) {
218→      return status.orchestratorStatus;
219→    }
220→    await Bun.sleep(intervalMs);
221→  }
222→
223→  throw new Error(
224→    `Session ${sessionId} did not reach status [${targetStatuses.join(", ")}] within ${timeoutMs}ms`,
225→  );
226→}
