  3→/**
  4→ * Tests for useAgentSession hook logic.
  5→ *
  6→ * Strategy: The hook's pure core is a state reducer (reduceAgentSessionEvent)
  7→ * that maps SSE events to AgentSessionState transitions. We test the reducer
  8→ * directly since it encodes all business rules. The EventSource wiring is a
  9→ * thin adapter tested via integration/manual.
 10→ *
 11→ * Behaviors under test:
 12→ *   1. agent_status events update status field
 13→ *   2. agent_file_change events increment filesChanged counter
 14→ *   3. agent_status with error sets error field
 15→ *   4. agent_stall_warning sets stallWarning
 16→ *   5. Any event resets stallWarning timer tracking (lastEventAt update)
 17→ *   6. Terminal statuses (completed, aborted, error) are recognized
 18→ */
 19→
 20→import {
 21→  reduceAgentSessionEvent,
 22→  createInitialState,
 23→  isTerminalStatus,
 24→  STALL_TIMEOUT_MS,
 25→  type AgentSessionState,
 26→} from "../../../../app/src/client/hooks/use-agent-session";
 27→
 28→// ---------------------------------------------------------------------------
 29→// Acceptance: full event sequence produces correct final state
 30→// ---------------------------------------------------------------------------
 31→
 32→describe("useAgentSession reducer (acceptance)", () => {
 33→  it("processes a full session lifecycle: spawning -> active -> file changes -> completed", () => {
 34→    let state = createInitialState("2026-03-07T10:00:00Z");
 35→
 36→    // Agent becomes active
 37→    state = reduceAgentSessionEvent(state, {
 38→      type: "agent_status",
 39→      sessionId: "s-1",
 40→      status: "active",
 41→    });
 42→    expect(state.status).toBe("active");
 43→    expect(state.filesChanged).toBe(0);
 44→
 45→    // Agent modifies files
 46→    state = reduceAgentSessionEvent(state, {
 47→      type: "agent_file_change",
 48→      sessionId: "s-1",
 49→      file: "src/main.ts",
 50→      changeType: "modified",
 51→    });
 52→    state = reduceAgentSessionEvent(state, {
 53→      type: "agent_file_change",
 54→      sessionId: "s-1",
 55→      file: "src/utils.ts",
 56→      changeType: "created",
 57→    });
 58→    expect(state.filesChanged).toBe(2);
 59→
 60→    // Agent completes
 61→    state = reduceAgentSessionEvent(state, {
 62→      type: "agent_status",
 63→      sessionId: "s-1",
 64→      status: "completed",
 65→    });
 66→    expect(state.status).toBe("completed");
 67→    expect(state.filesChanged).toBe(2);
 68→    expect(state.error).toBeUndefined();
 69→    expect(state.stallWarning).toBeUndefined();
 70→  });
 71→});
