import { describe, expect, test, beforeEach } from "bun:test";
import { RecordId } from "surrealdb";
import {
  sendSessionPrompt,
  clearHandleRegistry,
  createOrchestratorSession,
  type PromptSessionResult,
} from "../../../app/src/server/orchestrator/session-lifecycle";

// ---------------------------------------------------------------------------
// Stubs & helpers (same patterns as session-lifecycle.test.ts)
// ---------------------------------------------------------------------------

type SurrealSpy = {
  stub: unknown;
  updates: Array<{ record: unknown; merge: unknown }>;
  selects: Array<{ record: unknown }>;
};

function createSurrealSpy(responses: {
  sessionSelect?: Record<string, unknown>;
}): SurrealSpy {
  const spy: SurrealSpy = {
    stub: undefined,
    updates: [],
    selects: [],
  };

  spy.stub = {
    query(sql: string, _bindings?: Record<string, unknown>) {
      if (sql.includes("FROM $taskRecord")) {
        return Promise.resolve([[]]);
      }
      if (sql.includes("orchestrator_status") && sql.includes("agent_session")) {
        return Promise.resolve([[]]);
      }
      return Promise.resolve([[]]);
    },
    update(record: unknown) {
      return {
        merge(data: unknown) {
          spy.updates.push({ record, merge: data });
          return Promise.resolve({ id: record, ...(data as object) });
        },
      };
    },
    select(record: unknown) {
      spy.selects.push({ record });
      return Promise.resolve(responses.sessionSelect ?? undefined);
    },
    delete(_record: unknown) {
      return Promise.resolve();
    },
  };

  return spy;
}

function spawnOpenCodeStub(sessionId = "opencode-sess-1") {
  const abortCalls: string[] = [];
  const promptCalls: string[] = [];
  return {
    spawn: async (_config: unknown, _worktreePath: string, _taskId: string) => ({
      sessionId,
      abort: () => {
        abortCalls.push(sessionId);
      },
      sendPrompt: async (text: string) => {
        promptCalls.push(text);
      },
      eventStream: (async function* () {})(),
    }),
    abortCalls,
    promptCalls,
  };
}

function successShellExec() {
  return async (_cmd: string, _args: string[], _cwd: string) => ({
    exitCode: 0,
    stdout: "",
    stderr: "",
  });
}

function validateAssignmentStubOk(taskTitle = "Task", repoPath = "/repo") {
  return {
    fn: async (_surreal: unknown, workspaceId: string, taskId: string) => ({
      ok: true as const,
      validation: {
        taskRecord: new RecordId("task", taskId),
        workspaceRecord: new RecordId("workspace", workspaceId),
        taskStatus: "ready" as const,
        title: taskTitle,
        repoPath,
      },
    }),
  };
}

function createAgentSessionStub(returnSessionId = "agent-sess-1") {
  return {
    fn: async (_input: Record<string, unknown>) => ({
      session_id: returnSessionId,
    }),
  };
}

// ---------------------------------------------------------------------------
// Helper: create a session to populate the handle registry
// ---------------------------------------------------------------------------

async function seedSessionWithHandle(
  surrealSpy: SurrealSpy,
  agentSessionId: string,
  openCodeSessionId = "oc-sess-1",
) {
  const { spawn, promptCalls } = spawnOpenCodeStub(openCodeSessionId);
  const agentSessionStub = createAgentSessionStub(agentSessionId);
  const assignmentStub = validateAssignmentStubOk();

  await createOrchestratorSession({
    surreal: surrealSpy.stub as any,
    shellExec: successShellExec(),
    brainBaseUrl: "http://localhost:3000",
    workspaceId: "ws-1",
    taskId: "task-abc",
    authToken: "jwt-xyz",
    spawnOpenCode: spawn,
    validateAssignment: assignmentStub.fn,
    createAgentSession: agentSessionStub.fn as any,
  });

  return { promptCalls };
}

// ---------------------------------------------------------------------------
// Tests: sendSessionPrompt
// ---------------------------------------------------------------------------

describe("sendSessionPrompt", () => {
  beforeEach(() => {
    clearHandleRegistry();
  });

  test("delivers prompt to active session and returns delivered: true", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "active",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const { promptCalls } = await seedSessionWithHandle(surrealSpy, "sess-1");

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Please add input validation",
    });

    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.value.delivered).toBe(true);
    }
    expect(promptCalls).toContain("Please add input validation");
  });

  test("delivers prompt to idle session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "idle",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const { promptCalls } = await seedSessionWithHandle(surrealSpy, "sess-1");

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Continue with error handling",
    });

    expect(result.ok).toBe(true);
    expect(promptCalls).toContain("Continue with error handling");
  });

  test("delivers prompt to spawning session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "spawning",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const { promptCalls } = await seedSessionWithHandle(surrealSpy, "sess-1");

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Extra context for the task",
    });

    expect(result.ok).toBe(true);
    expect(promptCalls).toContain("Extra context for the task");
  });

  test("returns 404 for nonexistent session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: undefined,
    });

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "nonexistent",
      text: "Hello",
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.code).toBe("SESSION_NOT_FOUND");
      expect(result.error.httpStatus).toBe(404);
    }
  });

  test("returns 409 for completed session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "completed",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "More work please",
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.httpStatus).toBe(409);
    }
  });

  test("returns 409 for aborted session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "aborted",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Try again",
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.httpStatus).toBe(409);
    }
  });

  test("returns 409 for error session", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "error",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Retry",
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.httpStatus).toBe(409);
    }
  });

  test("returns 409 when handle is missing from registry", async () => {
    const surrealSpy = createSurrealSpy({
      sessionSelect: {
        id: new RecordId("agent_session", "sess-1"),
        orchestrator_status: "active",
        workspace: new RecordId("workspace", "ws-1"),
      },
    });
    // Note: no seedSessionWithHandle -- handle registry is empty

    const result = await sendSessionPrompt({
      surreal: surrealSpy.stub as any,
      sessionId: "sess-1",
      text: "Hello",
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.httpStatus).toBe(409);
      expect(result.error.message).toContain("handle");
    }
  });
});

import { describe, it, expect } from "bun:test";

/**
 * Tests for AgentSessionOutput data model -- token accumulation, file change
 * inline notifications, and prompt-triggered reset.
 *
 * Pure core under test: reduceAgentSessionEvent handles agent_token,
 * agent_file_change, and agent_prompt events to build the output entries
 * array that AgentSessionOutput renders.
 *
 * Behaviors:
 *   1. agent_token events accumulate text into output entries
 *   2. agent_file_change events appear as inline notifications in output
 *   3. Token accumulation resets when agent_prompt event arrives
 *   4. Output entries maintain chronological order across event types
 */

import {
  reduceAgentSessionEvent,
  createInitialState,
  type AgentSessionState,
  type OutputEntry,
} from "../../../../app/src/client/hooks/use-agent-session";

// ---------------------------------------------------------------------------
// Acceptance: full token stream lifecycle
// ---------------------------------------------------------------------------

describe("agent session output (acceptance)", () => {
  it("accumulates tokens, shows file changes inline, resets on new prompt", () => {
    let state = createInitialState("2026-03-07T10:00:00Z");

    // Agent becomes active
    state = reduceAgentSessionEvent(state, {
      type: "agent_status",
      sessionId: "s-1",
      status: "active",
    });

    // Token events stream in
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Hello ",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "world",
    });

    // Verify tokens accumulated
    const tokenEntries = state.outputEntries.filter(
      (e) => e.kind === "token",
    );
    expect(tokenEntries).toHaveLength(2);
    expect(tokenEntries[0].text).toBe("Hello ");
    expect(tokenEntries[1].text).toBe("world");

    // File change appears inline
    state = reduceAgentSessionEvent(state, {
      type: "agent_file_change",
      sessionId: "s-1",
      file: "src/main.ts",
      changeType: "modified",
    });

    const fileEntries = state.outputEntries.filter(
      (e) => e.kind === "file_change",
    );
    expect(fileEntries).toHaveLength(1);
    expect(fileEntries[0].file).toBe("src/main.ts");
    expect(fileEntries[0].changeType).toBe("modified");

    // More tokens after file change
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: " - done",
    });
    expect(state.outputEntries).toHaveLength(4); // 2 tokens + 1 file + 1 token

    // User sends a follow-up prompt -- resets output
    state = reduceAgentSessionEvent(state, {
      type: "agent_prompt",
      sessionId: "s-1",
      text: "Now fix the tests",
    });

    // Output entries reset, prompt appears as first entry
    const promptEntries = state.outputEntries.filter(
      (e) => e.kind === "prompt",
    );
    expect(promptEntries).toHaveLength(1);
    expect(promptEntries[0].text).toBe("Now fix the tests");

    // Previous tokens are gone (reset)
    const tokensAfterReset = state.outputEntries.filter(
      (e) => e.kind === "token",
    );
    expect(tokensAfterReset).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// Unit: individual output entry behaviors
// ---------------------------------------------------------------------------

describe("agent_token accumulation", () => {
  it("appends token text as output entry", () => {
    const state = createInitialState("2026-03-07T10:00:00Z");
    const next = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Hello",
    });

    expect(next.outputEntries).toHaveLength(1);
    expect(next.outputEntries[0].kind).toBe("token");
    expect(next.outputEntries[0].text).toBe("Hello");
  });

  it("preserves entry order across multiple tokens", () => {
    let state = createInitialState("2026-03-07T10:00:00Z");
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "first",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: " second",
    });

    expect(state.outputEntries).toHaveLength(2);
    expect(state.outputEntries[0].text).toBe("first");
    expect(state.outputEntries[1].text).toBe(" second");
  });
});

describe("file change inline notifications", () => {
  it("adds file change as output entry with file and changeType", () => {
    const state = createInitialState("2026-03-07T10:00:00Z");
    const next = reduceAgentSessionEvent(state, {
      type: "agent_file_change",
      sessionId: "s-1",
      file: "lib/utils.ts",
      changeType: "created",
    });

    expect(next.outputEntries).toHaveLength(1);
    const entry = next.outputEntries[0];
    expect(entry.kind).toBe("file_change");
    expect(entry.file).toBe("lib/utils.ts");
    expect(entry.changeType).toBe("created");
  });

  it("interleaves file changes among token entries", () => {
    let state = createInitialState("2026-03-07T10:00:00Z");
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Working...",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_file_change",
      sessionId: "s-1",
      file: "src/index.ts",
      changeType: "modified",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Done.",
    });

    expect(state.outputEntries).toHaveLength(3);
    expect(state.outputEntries[0].kind).toBe("token");
    expect(state.outputEntries[1].kind).toBe("file_change");
    expect(state.outputEntries[2].kind).toBe("token");
  });
});

describe("prompt-triggered output reset", () => {
  it("clears previous output entries and adds prompt entry", () => {
    let state = createInitialState("2026-03-07T10:00:00Z");
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Old output",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_prompt",
      sessionId: "s-1",
      text: "Do something else",
    });

    expect(state.outputEntries).toHaveLength(1);
    expect(state.outputEntries[0].kind).toBe("prompt");
    expect(state.outputEntries[0].text).toBe("Do something else");
  });

  it("allows new tokens after prompt reset", () => {
    let state = createInitialState("2026-03-07T10:00:00Z");
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "Old",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_prompt",
      sessionId: "s-1",
      text: "New prompt",
    });
    state = reduceAgentSessionEvent(state, {
      type: "agent_token",
      sessionId: "s-1",
      token: "New output",
    });

    expect(state.outputEntries).toHaveLength(2);
    expect(state.outputEntries[0].kind).toBe("prompt");
    expect(state.outputEntries[1].kind).toBe("token");
    expect(state.outputEntries[1].text).toBe("New output");
  });
});

import { describe, expect, test } from "bun:test";
import {
  createOrchestratorRouteHandlers,
  type OrchestratorRouteDeps,
} from "../../../app/src/server/orchestrator/routes";

// ---------------------------------------------------------------------------
// Stub deps (only the prompt-related path)
// ---------------------------------------------------------------------------

function createRouteDepsStub(overrides: Partial<OrchestratorRouteDeps> = {}): OrchestratorRouteDeps {
  return {
    createSession: async () => ({ ok: true, value: { agentSessionId: "s1", streamId: "st1", worktreeBranch: "agent/x" } }),
    getSessionStatus: async () => ({ ok: true, value: { orchestratorStatus: "active" as const } }),
    abortSession: async () => ({ ok: true, value: { aborted: true, sessionId: "s1" } }),
    acceptSession: async () => ({ ok: true, value: { accepted: true, sessionId: "s1" } }),
    getReview: async () => ({ ok: true, value: { taskTitle: "t", diff: {}, session: {} } }),
    rejectSession: async () => ({ ok: true, value: { rejected: true, continuing: true } }),
    sendPrompt: async () => ({ ok: true, value: { delivered: true } }),
    ...overrides,
  };
}

function makeRequest(body: object, sessionId = "sess-1"): Request & { params: Record<string, string> } {
  const req = new Request("http://localhost/api/orchestrator/ws-1/sessions/sess-1/prompt", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  }) as Request & { params: Record<string, string> };
  req.params = { workspaceId: "ws-1", sessionId };
  return req;
}

// ---------------------------------------------------------------------------
// Tests: prompt route handler
// ---------------------------------------------------------------------------

describe("prompt route handler", () => {
  test("returns 202 when prompt delivered successfully", async () => {
    const deps = createRouteDepsStub();
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({ text: "Add tests please" });

    const response = await handlers.prompt(request);

    expect(response.status).toBe(202);
    const body = await response.json();
    expect(body.delivered).toBe(true);
  });

  test("returns 400 when text is missing", async () => {
    const deps = createRouteDepsStub();
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({});

    const response = await handlers.prompt(request);

    expect(response.status).toBe(400);
  });

  test("returns 400 when text is empty string", async () => {
    const deps = createRouteDepsStub();
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({ text: "" });

    const response = await handlers.prompt(request);

    expect(response.status).toBe(400);
  });

  test("returns 400 when text is whitespace only", async () => {
    const deps = createRouteDepsStub();
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({ text: "   " });

    const response = await handlers.prompt(request);

    expect(response.status).toBe(400);
  });

  test("forwards session error (404) from lifecycle", async () => {
    const deps = createRouteDepsStub({
      sendPrompt: async () => ({
        ok: false,
        error: { code: "SESSION_NOT_FOUND" as const, message: "Session not found", httpStatus: 404 },
      }),
    });
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({ text: "Hello" });

    const response = await handlers.prompt(request);

    expect(response.status).toBe(404);
  });

  test("forwards session error (409) from lifecycle", async () => {
    const deps = createRouteDepsStub({
      sendPrompt: async () => ({
        ok: false,
        error: { code: "SESSION_ERROR" as const, message: "Terminal", httpStatus: 409 },
      }),
    });
    const handlers = createOrchestratorRouteHandlers(deps);
    const request = makeRequest({ text: "Hello" });

    const response = await handlers.prompt(request);

    expect(response.status).toBe(409);
  });
});

