246→    assignTaskToAgent,
247→  } = await import("../coding-agent-orchestrator/orchestrator-test-kit");
248→
249→  const user = await createTestUser(runtime.baseUrl, suffix);
250→  const workspace = await createTestWorkspace(runtime.baseUrl, user);
