  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→import { AgentSessionOutput } from "./AgentSessionOutput";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Pure core: view derivation
 17→// ---------------------------------------------------------------------------
 18→
 19→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 20→
 21→export type AgentStatusViewHidden = { variant: "hidden" };
 22→export type AgentStatusViewAssign = { variant: "assign" };
 23→export type AgentStatusViewActive = {
 24→  variant: "active";
 25→  agentSessionId: string;
 26→  orchestratorStatus: string;
 27→  filesChangedCount: number;
 28→  streamUrl: string;
 29→  startedAt: string;
 30→};
 31→
 32→export type AgentStatusView =
 33→  | AgentStatusViewHidden
 34→  | AgentStatusViewAssign
 35→  | AgentStatusViewActive;
 36→
 37→export type DeriveAgentStatusInput = {
 38→  entityKind: string;
 39→  entityStatus: string;
 40→  agentSession?: AgentSessionSummary;
 41→};
 42→
 43→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 44→  if (input.entityKind !== "task") {
 45→    return { variant: "hidden" };
 46→  }
 47→
 48→  if (input.agentSession) {
 49→    return {
 50→      variant: "active",
 51→      agentSessionId: input.agentSession.agentSessionId,
 52→      orchestratorStatus: input.agentSession.orchestratorStatus,
 53→      filesChangedCount: input.agentSession.filesChangedCount,
 54→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 55→      startedAt: input.agentSession.startedAt,
 56→    };
 57→  }
 58→
 59→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 60→    return { variant: "assign" };
 61→  }
 62→
 63→  return { variant: "hidden" };
 64→}
