 85→// ---------------------------------------------------------------------------
 86→
 87→export function AgentStatusSection({
 88→  entityId,
 89→  workspaceId,
 90→  entityKind,
 91→  entityStatus,
 92→  agentSession,
 93→}: {
 94→  entityId: string;
 95→  workspaceId: string;
 96→  entityKind: EntityKind;
 97→  entityStatus: string;
 98→  agentSession?: AgentSessionSummary;
 99→}) {
100→  const repoPath = useWorkspaceState((s) => s.repoPath);
101→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
102→  const [assigning, setAssigning] = useState(false);
103→  const [assignError, setAssignError] = useState<string | undefined>();
104→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
105→  const [repoPathInput, setRepoPathInput] = useState("");
106→  const [settingRepoPath, setSettingRepoPath] = useState(false);
107→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
108→
109→  // Derive the initial view from props
110→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
111→
112→  // If we have an assign result, use its stream URL; otherwise use session from props.
113→  // streamUrl is a dependency of useAgentSession's useEffect, so when assignResult
114→  // arrives and triggers a re-render, the hook will start the SSE subscription.
115→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
116→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
117→
118→  // SSE subscription -- only active when we have a stream URL
119→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
120→
121→  // Determine what to show
122→  const hasActiveStream = streamUrl !== undefined;
123→
124→  if (initialView.variant === "hidden" && !hasActiveStream) {
125→    return undefined;
126→  }
127→
128→  async function handleAssign() {
129→    if (assigning) return;
130→    setAssigning(true);
131→    setAssignError(undefined);
132→    try {
133→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
134→      const result = await assignAgent(workspaceId, rawTaskId);
135→      setAssignResult(result);
136→    } catch (err) {
137→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
138→    } finally {
139→      setAssigning(false);
140→    }
141→  }
142→
143→  // Show active session view (either from props or from fresh assignment)
144→  if (hasActiveStream) {
145→    const displayStatus = sessionState.status;
146→    const displayFiles = initialView.variant === "active"
147→      ? initialView.filesChangedCount + sessionState.filesChanged
148→      : sessionState.filesChanged;
149→
150→    return (
151→      <div className="entity-detail-section agent-status-section">
152→        <h4>Agent</h4>
153→        <div className="agent-status-row">
154→          <span className={`agent-status-badge agent-status-${displayStatus}`} data-testid="agent-status-badge">
155→            {statusLabel(displayStatus)}
156→          </span>
157→          {displayFiles > 0 ? (
158→            <span className="agent-file-count" data-testid="agent-file-count">
159→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
160→            </span>
161→          ) : undefined}
162→        </div>
163→        <AgentSessionOutput
164→          outputEntries={sessionState.outputEntries}
165→          status={displayStatus}
166→        />
167→        {sessionState.stallWarning ? (
168→          <p className="agent-stall-warning" data-testid="agent-stall-warning">
169→            Agent may be stalled (no activity for {sessionState.stallWarning.stallDurationSeconds}s)
170→          </p>
171→        ) : undefined}
172→        {sessionState.connectionError ? (
173→          <p className="agent-connection-error">{sessionState.connectionError}</p>
174→        ) : undefined}
175→        {displayStatus === "idle" ? (
176→          <a
177→            className="agent-review-link"
178→            data-testid="agent-review-link"
179→            href={`/review/${encodeURIComponent(
180→              assignResult?.agentSessionId
181→                ?? (initialView.variant === "active" ? initialView.agentSessionId : ""),
182→            )}`}
183→          >
184→            Review
185→          </a>
186→        ) : undefined}
187→      </div>
188→    );
189→  }
190→
191→  // Show assign button (with missing repo_path banner when applicable)
192→  if (initialView.variant === "assign") {
193→    const missingRepoPath = repoPath === undefined;
194→
195→    return (
196→      <div className="entity-detail-section agent-status-section">
197→        <h4>Agent</h4>
198→        {missingRepoPath ? (
199→          <div className="agent-repo-path-banner" data-testid="agent-repo-path-banner">
200→            <p>Repository path is not configured for this workspace. Set it before assigning an agent.</p>
201→            <form
202→              className="agent-repo-path-form"
203→              data-testid="agent-repo-path-form"
204→              onSubmit={async (e) => {
205→                e.preventDefault();
206→                const trimmed = repoPathInput.trim();
207→                if (!trimmed || settingRepoPath) return;
208→                setSettingRepoPath(true);
209→                setRepoPathError(undefined);
210→                try {
211→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
212→                    method: "POST",
213→                    headers: { "Content-Type": "application/json" },
214→                    body: JSON.stringify({ path: trimmed }),
215→                  });
216→                  if (!res.ok) {
217→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
218→                    setRepoPathError(body.error ?? "Failed to set repository path");
219→                    return;
220→                  }
221→                  setStoreRepoPath(trimmed);
222→                  setRepoPathInput("");
223→                } catch {
224→                  setRepoPathError("Network error");
225→                } finally {
226→                  setSettingRepoPath(false);
227→                }
228→              }}
229→            >
230→              <input
231→                type="text"
232→                className="agent-repo-path-input"
233→                data-testid="agent-repo-path-input"
234→                placeholder="/path/to/git/repository"
235→                value={repoPathInput}
236→                onChange={(e) => setRepoPathInput(e.target.value)}
237→                disabled={settingRepoPath}
238→              />
239→              <button
240→                type="submit"
241→                className="agent-repo-path-action"
242→                data-testid="agent-repo-path-action"
243→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
244→              >
245→                {settingRepoPath ? "Setting..." : "Set Path"}
246→              </button>
247→            </form>
248→            {repoPathError ? (
249→              <p className="agent-repo-path-error" data-testid="agent-repo-path-error">{repoPathError}</p>
250→            ) : undefined}
251→          </div>
252→        ) : undefined}
253→        <button
254→          type="button"
255→          className="agent-assign-button"
256→          data-testid="agent-assign-button"
257→          disabled={assigning || missingRepoPath}
258→          onClick={handleAssign}
259→        >
260→          {assigning ? "Assigning..." : "Assign Agent"}
261→        </button>
262→        {assignError ? (
263→          <p className="agent-assign-error" data-testid="agent-assign-error">{assignError}</p>
264→        ) : undefined}
265→      </div>
266→    );
267→  }
268→
269→  return undefined;
270→}
