 24→// ---------------------------------------------------------------------------
 25→// Component
 26→// ---------------------------------------------------------------------------
 27→
 28→export function AgentSessionOutput({
 29→  outputEntries,
 30→  status,
 31→}: {
 32→  outputEntries: OutputEntry[];
 33→  status: AgentSessionStatus;
 34→}) {
 35→  const containerRef = useRef<HTMLDivElement>(null);
 36→  const isStreaming = !isTerminalStatus(status) && status !== "idle";
 37→
 38→  // Auto-scroll to bottom when new entries arrive during active streaming
 39→  useEffect(() => {
 40→    if (isStreaming && containerRef.current) {
 41→      containerRef.current.scrollTop = containerRef.current.scrollHeight;
 42→    }
 43→  }, [outputEntries.length, isStreaming]);
 44→
 45→  if (outputEntries.length === 0) {
 46→    return (
 47→      <div
 48→        className="agent-session-output agent-session-output--empty"
 49→        data-testid="agent-session-output"
 50→      >
 51→        <p className="agent-session-output__placeholder">
 52→          Waiting for agent output...
 53→        </p>
 54→      </div>
 55→    );
 56→  }
 57→
 58→  return (
 59→    <div
 60→      ref={containerRef}
 61→      className="agent-session-output"
 62→      data-testid="agent-session-output"
 63→    >
