271→
272→type CreateSessionInput = {
273→  surreal: Surreal;
274→  shellExec: ShellExec;
275→  brainBaseUrl: string;
276→  workspaceId: string;
277→  taskId: string;
278→  authToken: string;
279→  spawnOpenCode?: SpawnOpenCodeFn;
280→  validateAssignment: (
281→    surreal: Surreal,
282→    workspaceId: string,
283→    taskId: string,
284→  ) => Promise<AssignmentResult>;
285→  createAgentSession: (input: {
286→    surreal: Surreal;
287→    agent: string;
288→    workspaceRecord: RecordId<"workspace", string>;
289→    taskId?: string;
290→  }) => Promise<{ session_id: string }>;
291→};
292→
293→export async function createOrchestratorSession(
294→  input: CreateSessionInput,
295→): Promise<OrchestratorSessionResult> {
296→  // 1. Validate assignment eligibility
297→  const assignmentResult = await input.validateAssignment(
298→    input.surreal,
299→    input.workspaceId,
300→    input.taskId,
301→  );
302→
303→  if (!assignmentResult.ok) {
304→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
305→  }
306→
307→  const { validation } = assignmentResult;
308→  const taskSlug = slugFromTitle(validation.title);
309→  const repoRoot = validation.repoPath;
310→
311→  // 2. Create worktree
312→  const worktreeResult = await createWorktree(
313→    input.shellExec,
314→    repoRoot,
315→    taskSlug,
316→  );
317→
318→  if (!worktreeResult.ok) {
319→    return {
320→      ok: false,
321→      error: worktreeError(worktreeResult.error.message),
322→    };
323→  }
324→
325→  const { branchName, worktreePath } = worktreeResult.value;
326→
327→  // 3. Create agent_session record
328→  const { session_id: agentSessionId } = await input.createAgentSession({
329→    surreal: input.surreal,
330→    agent: "opencode",
331→    workspaceRecord: validation.workspaceRecord,
332→    taskId: input.taskId,
333→  });
334→
335→  const streamId = generateStreamId(agentSessionId);
336→
337→  // 4. Build config and spawn OpenCode
338→  const config = buildOpencodeConfig({
339→    brainBaseUrl: input.brainBaseUrl,
340→    workspaceId: input.workspaceId,
341→    authToken: input.authToken,
342→  });
343→
344→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
345→  let handle: OpenCodeHandle;
346→  try {
347→    handle = await spawnFn(config, worktreePath, input.taskId);
348→  } catch (err) {
349→    // Rollback: remove worktree and delete agent_session on spawn failure
350→    await removeWorktree(input.shellExec, repoRoot, branchName);
351→    const sessionRecord = new RecordId("agent_session", agentSessionId);
352→    await input.surreal.delete(sessionRecord);
353→    return {
354→      ok: false,
355→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
356→    };
357→  }
358→
359→  // 5. Register handle for later abort
360→  handleRegistry.set(agentSessionId, handle);
361→
362→  // 6. Update agent_session with orchestrator fields
363→  const sessionRecord = new RecordId("agent_session", agentSessionId);
364→  await input.surreal.update(sessionRecord).merge({
365→    orchestrator_status: "spawning" as OrchestratorStatus,
366→    worktree_branch: branchName,
367→    worktree_path: worktreePath,
368→    opencode_session_id: handle.sessionId,
369→    stream_id: streamId,
370→  });
371→
372→  return {
373→    ok: true,
374→    value: {
375→      agentSessionId,
376→      streamId,
377→      worktreeBranch: branchName,
378→    },
379→  };
380→}
