382→// Default spawn -- placeholder for production use
383→async function defaultSpawnOpenCode(
384→  _config: OpencodeConfig,
385→  _worktreePath: string,
386→  _taskId: string,
387→): Promise<OpenCodeHandle> {
388→  throw new Error(
389→    "spawnOpenCode not provided -- must be injected for production use",
390→  );
391→}
