424→// ---------------------------------------------------------------------------
425→// abortOrchestratorSession
426→// ---------------------------------------------------------------------------
427→
428→type AbortSessionInput = {
429→  surreal: Surreal;
430→  shellExec: ShellExec;
431→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
432→  sessionId: string;
433→  endAgentSession: (input: {
434→    surreal: Surreal;
435→    workspaceRecord: RecordId<"workspace", string>;
436→    sessionId: string;
437→    summary: string;
438→  }) => Promise<{ session_id: string; ended: boolean }>;
439→};
440→
441→export async function abortOrchestratorSession(
442→  input: AbortSessionInput,
443→): Promise<AbortSessionResult> {
444→  const lookup = await lookupSession(input.surreal, input.sessionId);
445→  if (!lookup.ok) {
446→    return { ok: false, error: lookup.error };
447→  }
448→  const { session, record: sessionRecord } = lookup;
449→
450→  // 1. Kill the OpenCode process if handle exists
451→  const handle = handleRegistry.get(input.sessionId);
452→  if (handle) {
453→    handle.abort();
454→    handleRegistry.delete(input.sessionId);
455→  }
456→
457→  // 2. Update orchestrator_status to aborted
458→  await input.surreal.update(sessionRecord).merge({
459→    orchestrator_status: "aborted" as OrchestratorStatus,
460→  });
461→
462→  // 3. Remove worktree if branch name exists
463→  if (session.worktree_branch && session.workspace) {
464→    const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
465→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
466→  }
467→
468→  // 4. Return task to ready
469→  if (session.task_id) {
470→    await input.surreal.update(session.task_id).merge({
471→      status: "ready",
472→      updated_at: new Date(),
473→    });
474→  }
475→
476→  // 5. End the agent session
477→  if (!session.workspace) {
478→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
479→  }
480→  await input.endAgentSession({
481→    surreal: input.surreal,
482→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
483→    sessionId: input.sessionId,
484→    summary: "Session aborted",
485→  });
486→
487→  return {
488→    ok: true,
489→    value: {
490→      aborted: true,
491→      sessionId: input.sessionId,
492→    },
493→  };
494→}
