497→// acceptOrchestratorSession
498→// ---------------------------------------------------------------------------
499→
500→type AcceptSessionInput = {
501→  surreal: Surreal;
502→  sessionId: string;
503→  summary: string;
504→  endAgentSession: (input: {
505→    surreal: Surreal;
506→    workspaceRecord: RecordId<"workspace", string>;
507→    sessionId: string;
508→    summary: string;
509→  }) => Promise<{ session_id: string; ended: boolean }>;
510→};
511→
512→export async function acceptOrchestratorSession(
513→  input: AcceptSessionInput,
514→): Promise<AcceptSessionResult> {
515→  const lookup = await lookupSession(input.surreal, input.sessionId);
516→  if (!lookup.ok) {
517→    return { ok: false, error: lookup.error };
518→  }
519→  const { session, record: sessionRecord, status } = lookup;
520→
521→  if (!ACCEPTABLE_STATUSES.has(status)) {
522→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
523→  }
524→
525→  // 1. Update orchestrator_status to completed
526→  await input.surreal.update(sessionRecord).merge({
527→    orchestrator_status: "completed" as OrchestratorStatus,
528→  });
529→
530→  // 2. Mark task as done
531→  if (session.task_id) {
532→    await input.surreal.update(session.task_id).merge({
533→      status: "done",
534→      updated_at: new Date(),
535→    });
536→  }
537→
538→  // 3. Clean up handle registry
539→  handleRegistry.delete(input.sessionId);
540→
541→  // 4. End the agent session
542→  if (!session.workspace) {
543→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
544→  }
545→  await input.endAgentSession({
546→    surreal: input.surreal,
547→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
548→    sessionId: input.sessionId,
549→    summary: input.summary,
550→  });
551→
552→  return {
553→    ok: true,
554→    value: {
555→      accepted: true,
556→      sessionId: input.sessionId,
557→    },
558→  };
559→}
