565→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
566→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
567→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
568→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
