570→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
571→  return {
572→    code: "SESSION_ERROR",
573→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
574→    httpStatus: 409,
575→  };
576→}
577→
578→function sessionAborted(sessionId: string): SessionError {
579→  return {
580→    code: "SESSION_ERROR",
581→    message: `Session ${sessionId} has been aborted`,
582→    httpStatus: 409,
583→  };
584→}
