587→// getOrchestratorReview
588→// ---------------------------------------------------------------------------
589→
590→type GetReviewInput = {
591→  surreal: Surreal;
592→  sessionId: string;
593→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
594→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
595→  getTaskTitle: (taskId: string) => Promise<string>;
596→};
597→
598→export async function getOrchestratorReview(
599→  input: GetReviewInput,
600→): Promise<ReviewResult> {
601→  const lookup = await lookupSession(input.surreal, input.sessionId);
602→  if (!lookup.ok) {
603→    return { ok: false, error: lookup.error };
604→  }
605→  const { session, status } = lookup;
606→
607→  if (status === "aborted") {
608→    return { ok: false, error: sessionAborted(input.sessionId) };
609→  }
610→
611→  if (!REVIEWABLE_STATUSES.has(status)) {
612→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
613→  }
614→
615→  // Get diff from the branch
616→  const branchName = session.worktree_branch ?? "";
617→  if (!session.workspace) {
618→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
619→  }
620→  const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
621→  const diffResult = await input.getDiff(repoRoot, branchName);
622→
623→  const diff = diffResult.ok
624→    ? diffResult.value
625→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
626→
627→  // Get task title
628→  const taskId = session.task_id ? (session.task_id.id as string) : "";
629→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
630→
631→  return {
632→    ok: true,
633→    value: {
634→      taskTitle,
635→      diff,
636→      session: {
637→        orchestratorStatus: status,
638→        ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
639→        ...(session.started_at ? { startedAt: session.started_at } : {}),
640→        ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
641→      },
642→    },
643→  };
644→}
