650→type RejectSessionInput = {
651→  surreal: Surreal;
652→  sessionId: string;
653→  feedback: string;
654→};
655→
656→export async function rejectOrchestratorSession(
657→  input: RejectSessionInput,
658→): Promise<RejectSessionResult> {
659→  const lookup = await lookupSession(input.surreal, input.sessionId);
660→  if (!lookup.ok) {
661→    return { ok: false, error: lookup.error };
662→  }
663→  const { session, record: sessionRecord, status } = lookup;
664→
665→  if (!REJECTABLE_STATUSES.has(status)) {
666→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
667→  }
668→
669→  // 1. Update session status to active (agent resumes work)
670→  await input.surreal.update(sessionRecord).merge({
671→    orchestrator_status: "active" as OrchestratorStatus,
672→    last_feedback: input.feedback,
673→  });
674→
675→  // 2. Return task to in_progress
676→  if (session.task_id) {
677→    await input.surreal.update(session.task_id).merge({
678→      status: "in_progress",
679→      updated_at: new Date(),
680→    });
681→  }
682→
683→  return {
684→    ok: true,
685→    value: {
686→      rejected: true,
687→      continuing: true,
688→    },
689→  };
690→}
