707→    return { ok: false, error: lookup.error };
708→  }
709→  const { status } = lookup;
710→
711→  if (!PROMPTABLE_STATUSES.has(status)) {
712→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
713→  }
714→
715→  const handle = handleRegistry.get(input.sessionId);
716→  if (!handle) {
717→    return {
718→      ok: false,
719→      error: {
720→        code: "SESSION_ERROR",
721→        message: `Cannot prompt session ${input.sessionId}: agent handle not available (server may have restarted)`,
722→        httpStatus: 409,
723→      },
724→    };
725→  }
726→
727→  // Fire-and-forget: deliver prompt to the agent process
728→  handle.sendPrompt(input.text).catch(() => {
729→    // Prompt delivery failure is non-fatal; the session continues
730→  });
731→
732→  return {
733→    ok: true,
734→    value: { delivered: true },
735→  };
736→}
737→

  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function statusResponse(
 87→  sessionId: string,
 88→  value: {
 89→    orchestratorStatus: string;
 90→    worktreeBranch?: string;
 91→    worktreePath?: string;
 92→    startedAt?: string;
 93→    lastEventAt?: string;
 94→    error?: string;
 95→  },
 96→): Response {
 97→  return jsonResponse(
 98→    {
 99→      agentSessionId: sessionId,
100→      orchestratorStatus: value.orchestratorStatus,
101→      ...(value.worktreeBranch ? { worktreeBranch: value.worktreeBranch } : {}),
102→      ...(value.worktreePath ? { worktreePath: value.worktreePath } : {}),
103→      ...(value.startedAt ? { startedAt: value.startedAt } : {}),
104→      ...(value.lastEventAt ? { lastEventAt: value.lastEventAt } : {}),
105→      ...(value.error ? { error: value.error } : {}),
106→    },
107→    200,
108→  );
109→}
110→
111→function acceptResponse(): Response {
112→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
113→}
114→
115→function abortResponse(): Response {
116→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
117→}
118→
119→function reviewResponse(value: {
120→  taskTitle: string;
121→  diff: unknown;
122→  session: unknown;
123→}): Response {
124→  return jsonResponse(value, 200);
125→}
126→
127→function rejectResponse(): Response {
128→  return jsonResponse({ rejected: true, continuing: true }, 200);
129→}
130→
131→function promptResponse(): Response {
132→  return jsonResponse({ delivered: true }, 202);
133→}
134→
135→function sessionErrorResponse(error: {
136→  message: string;
137→  httpStatus: number;
138→}): Response {
139→  return jsonError(error.message, error.httpStatus);
140→}
141→
142→// ---------------------------------------------------------------------------
143→// Route handler factory
144→// ---------------------------------------------------------------------------
145→
146→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
147→  const assign: RouteHandler = async (request) => {
148→    const workspaceId = request.params.workspaceId;
149→    const body = await parseJsonBody<AssignBody>(request);
150→
151→    if (!body?.taskId) {
152→      return jsonError("taskId is required", 400);
153→    }
154→
155→    const authToken = extractAuthToken(request);
156→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
157→
158→    if (!result.ok) {
159→      return sessionErrorResponse(result.error);
160→    }
161→
162→    return assignResponse(workspaceId, result.value);
163→  };
164→
165→  const status: RouteHandler = async (request) => {
166→    const sessionId = request.params.sessionId;
167→    const result = await deps.getSessionStatus(sessionId);
168→
169→    if (!result.ok) {
170→      return sessionErrorResponse(result.error);
171→    }
172→
173→    return statusResponse(sessionId, result.value);
174→  };
175→
176→  const accept: RouteHandler = async (request) => {
177→    const sessionId = request.params.sessionId;
178→    const body = await parseJsonBody<AcceptBody>(request);
179→    const summary = body?.summary ?? "";
180→
181→    const result = await deps.acceptSession(sessionId, summary);
182→
183→    if (!result.ok) {
184→      return sessionErrorResponse(result.error);
185→    }
186→
187→    return acceptResponse();
188→  };
189→
190→  const abort: RouteHandler = async (request) => {
191→    const sessionId = request.params.sessionId;
192→    const result = await deps.abortSession(sessionId);
193→
194→    if (!result.ok) {
195→      return sessionErrorResponse(result.error);
196→    }
197→
198→    return abortResponse();
199→  };
200→
201→  const review: RouteHandler = async (request) => {
202→    const sessionId = request.params.sessionId;
203→    const result = await deps.getReview(sessionId);
204→
205→    if (!result.ok) {
206→      return sessionErrorResponse(result.error);
207→    }
208→
209→    return reviewResponse(result.value);
210→  };
211→
212→  const reject: RouteHandler = async (request) => {
213→    const sessionId = request.params.sessionId;
214→    const body = await parseJsonBody<RejectBody>(request);
215→
216→    if (!body?.feedback || body.feedback.trim() === "") {
217→      return jsonError("feedback is required", 400);
218→    }
219→
220→    const result = await deps.rejectSession(sessionId, body.feedback);
221→
222→    if (!result.ok) {
223→      return sessionErrorResponse(result.error);
224→    }
225→
226→    return rejectResponse();
227→  };
228→
229→  const prompt: RouteHandler = async (request) => {
230→    const sessionId = request.params.sessionId;
231→    const body = await parseJsonBody<PromptBody>(request);
232→
233→    if (!body?.text || body.text.trim() === "") {
234→      return jsonError("text is required", 400);
235→    }
236→
237→    const result = await deps.sendPrompt(sessionId, body.text);
238→
239→    if (!result.ok) {
240→      return sessionErrorResponse(result.error);
241→    }
242→
243→    return promptResponse();
244→  };
245→
246→  return { assign, status, accept, abort, review, reject, prompt };
247→}
248→
249→// ---------------------------------------------------------------------------
250→// SSE stream route handler factory
251→// ---------------------------------------------------------------------------
252→
253→export type StreamRouteDeps = {
254→  sseRegistry: SseRegistry;
255→};
256→
257→export function createStreamRouteHandler(deps: StreamRouteDeps) {
258→  const stream: RouteHandler = async (request) => {
259→    const streamId = request.params.streamId;
260→
261→    if (!streamId) {
262→      return jsonError("streamId is required", 400);
263→    }
264→
265→    return deps.sseRegistry.handleStreamRequest(streamId);
266→  };
267→
268→  return { stream };
269→}
270→
271→// ---------------------------------------------------------------------------
272→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
273→// ---------------------------------------------------------------------------
274→
275→export type OrchestratorWiringDeps = {
276→  surreal: import("surrealdb").Surreal;
277→  shellExec: import("./worktree-manager").ShellExec;
278→  brainBaseUrl: string;
279→  sseRegistry?: SseRegistry;
280→};
281→
282→export function wireOrchestratorRoutes(
283→  wiringDeps: OrchestratorWiringDeps,
284→): {
285→  assign: RouteHandler;
286→  status: RouteHandler;
287→  accept: RouteHandler;
288→  abort: RouteHandler;
289→  review: RouteHandler;
290→  reject: RouteHandler;
291→  prompt: RouteHandler;
292→  stream?: RouteHandler;
293→} {
294→  // Lazy imports to keep module boundary clean
295→  const lifecycleImport = import("./session-lifecycle");
296→  const queriesImport = import("../mcp/mcp-queries");
297→  const guardImport = import("./assignment-guard");
298→
299→  // Helper: resolve repo_path from workspace record
300→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
301→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
302→      `SELECT repo_path FROM $ws;`,
303→      { ws: workspaceRecord },
304→    );
305→    const repoPath = rows[0]?.repo_path;
306→    if (!repoPath) {
307→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
308→    }
309→    return repoPath;
310→  };
311→
312→  // Use mock spawn for acceptance tests, production spawn otherwise
313→  const spawnOpenCodeImport = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true"
314→    ? Promise.resolve({
315→        spawnOpenCode: async () => ({
316→          sessionId: crypto.randomUUID(),
317→          abort: () => {},
318→          sendPrompt: async () => {},
319→          eventStream: (async function* () {})(),
320→        }),
321→      })
322→    : import("./spawn-opencode");
323→
324→  const routeDeps: OrchestratorRouteDeps = {
325→    createSession: async (workspaceId, taskId, authToken) => {
326→      const [lifecycle, queries, guard, { spawnOpenCode }] = await Promise.all([
327→        lifecycleImport,
328→        queriesImport,
329→        guardImport,
330→        spawnOpenCodeImport,
331→      ]);
332→      return lifecycle.createOrchestratorSession({
333→        surreal: wiringDeps.surreal,
334→        shellExec: wiringDeps.shellExec,
335→        brainBaseUrl: wiringDeps.brainBaseUrl,
336→        workspaceId,
337→        taskId,
338→        authToken,
339→        validateAssignment: guard.validateAssignment,
340→        createAgentSession: queries.createAgentSession,
341→        spawnOpenCode,
342→      });
343→    },
344→
345→    getSessionStatus: async (sessionId) => {
346→      const lifecycle = await lifecycleImport;
347→      return lifecycle.getOrchestratorSessionStatus({
348→        surreal: wiringDeps.surreal,
349→        sessionId,
350→      });
351→    },
352→
353→    abortSession: async (sessionId) => {
354→      const [lifecycle, queries] = await Promise.all([
355→        lifecycleImport,
356→        queriesImport,
357→      ]);
358→      return lifecycle.abortOrchestratorSession({
359→        surreal: wiringDeps.surreal,
360→        shellExec: wiringDeps.shellExec,
361→        resolveRepoRoot,
362→        sessionId,
363→        endAgentSession: queries.endAgentSession,
364→      });
365→    },
366→
367→    acceptSession: async (sessionId, summary) => {
368→      const [lifecycle, queries] = await Promise.all([
369→        lifecycleImport,
370→        queriesImport,
371→      ]);
372→      return lifecycle.acceptOrchestratorSession({
373→        surreal: wiringDeps.surreal,
374→        sessionId,
375→        summary,
376→        endAgentSession: queries.endAgentSession,
377→      });
378→    },
379→
380→    getReview: async (sessionId) => {
381→      const [lifecycle, worktreeManager] = await Promise.all([
382→        lifecycleImport,
383→        import("./worktree-manager"),
384→      ]);
385→      return lifecycle.getOrchestratorReview({
386→        surreal: wiringDeps.surreal,
387→        sessionId,
388→        resolveRepoRoot,
389→        getDiff: (repoRoot: string, branchName: string) =>
390→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
391→        getTaskTitle: async (taskId: string) => {
392→          const { RecordId } = await import("surrealdb");
393→          const taskRecord = new RecordId("task", taskId);
394→          const rows = (await wiringDeps.surreal.query(
395→            `SELECT title FROM $task;`,
396→            { task: taskRecord },
397→          )) as Array<Array<{ title: string }>>;
398→          return rows[0]?.[0]?.title ?? "";
399→        },
400→      });
401→    },
402→
403→    rejectSession: async (sessionId, feedback) => {
404→      const lifecycle = await lifecycleImport;
405→      return lifecycle.rejectOrchestratorSession({
406→        surreal: wiringDeps.surreal,
407→        sessionId,
408→        feedback,
409→      });
410→    },
411→
412→    sendPrompt: async (sessionId, text) => {
413→      const lifecycle = await lifecycleImport;
414→      return lifecycle.sendSessionPrompt({
415→        surreal: wiringDeps.surreal,
416→        sessionId,
417→        text,
418→      });
419→    },
420→  };
421→
422→  const handlers = createOrchestratorRouteHandlers(routeDeps);
423→
424→  const streamHandler = wiringDeps.sseRegistry
425→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
426→    : undefined;
427→
428→  return {
429→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
430→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
431→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
432→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
433→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
434→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
435→    prompt: withRequestLogging("orchestrator.prompt", "POST", handlers.prompt),
436→    ...(streamHandler
437→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
438→      : {}),
439→  };
440→}
441→

  1→/**
  2→ * AgentSessionOutput -- renders accumulated agent output as streaming text
  3→ * with inline file change notifications.
  4→ *
  5→ * Pure presentational component. All state managed by useAgentSession hook.
  6→ * Auto-scrolls to latest content while streaming is active.
  7→ */
  8→
  9→import { useEffect, useRef } from "react";
 10→import type { OutputEntry } from "../../hooks/use-agent-session";
 11→import { isTerminalStatus, type AgentSessionStatus } from "../../hooks/use-agent-session";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Pure core: derive display text from output entries
 15→// ---------------------------------------------------------------------------
 16→
 17→export function renderTokenText(entries: OutputEntry[]): string {
 18→  return entries
 19→    .filter((e): e is Extract<OutputEntry, { kind: "token" }> => e.kind === "token")
 20→    .map((e) => e.text)
 21→    .join("");
 22→}
 23→
 24→// ---------------------------------------------------------------------------
 25→// Component
 26→// ---------------------------------------------------------------------------
 27→
 28→export function AgentSessionOutput({
 29→  outputEntries,
 30→  status,
 31→}: {
 32→  outputEntries: OutputEntry[];
 33→  status: AgentSessionStatus;
 34→}) {
 35→  const containerRef = useRef<HTMLDivElement>(null);
 36→  const isStreaming = !isTerminalStatus(status) && status !== "idle";
 37→
 38→  // Auto-scroll to bottom when new entries arrive during active streaming
 39→  useEffect(() => {
 40→    if (isStreaming && containerRef.current) {
 41→      containerRef.current.scrollTop = containerRef.current.scrollHeight;
 42→    }
 43→  }, [outputEntries.length, isStreaming]);
 44→
 45→  if (outputEntries.length === 0) {
 46→    return (
 47→      <div
 48→        className="agent-session-output agent-session-output--empty"
 49→        data-testid="agent-session-output"
 50→      >
 51→        <p className="agent-session-output__placeholder">
 52→          Waiting for agent output...
 53→        </p>
 54→      </div>
 55→    );
 56→  }
 57→
 58→  return (
 59→    <div
 60→      ref={containerRef}
 61→      className="agent-session-output"
 62→      data-testid="agent-session-output"
 63→    >
 64→      {outputEntries.map((entry, index) => {
 65→        switch (entry.kind) {
 66→          case "token":
 67→            return (
 68→              <span
 69→                key={index}
 70→                className="agent-session-output__token"
 71→                data-testid="agent-output-token"
 72→              >
 73→                {entry.text}
 74→              </span>
 75→            );
 76→          case "file_change":
 77→            return (
 78→              <div
 79→                key={index}
 80→                className="agent-session-output__file-change"
 81→                data-testid="agent-output-file-change"
 82→              >
 83→                <span className="agent-session-output__file-icon">
 84→                  {entry.changeType === "created"
 85→                    ? "+"
 86→                    : entry.changeType === "deleted"
 87→                      ? "-"
 88→                      : "~"}
 89→                </span>
 90→                <span className="agent-session-output__file-path">
 91→                  {entry.file}
 92→                </span>
 93→              </div>
 94→            );
 95→          case "prompt":
 96→            return (
 97→              <div
 98→                key={index}
 99→                className="agent-session-output__prompt"
100→                data-testid="agent-output-prompt"
101→              >
102→                {entry.text}
103→              </div>
104→            );
105→        }
106→      })}
107→    </div>
108→  );
109→}
