  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→import { AgentSessionPanel } from "./AgentSessionPanel";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Pure core: view derivation
 17→// ---------------------------------------------------------------------------
 18→
 19→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 20→
 21→export type AgentStatusViewHidden = { variant: "hidden" };
 22→export type AgentStatusViewAssign = { variant: "assign" };
 23→export type AgentStatusViewActive = {
 24→  variant: "active";
 25→  agentSessionId: string;
 26→  orchestratorStatus: string;
 27→  filesChangedCount: number;
 28→  streamUrl: string;
 29→  startedAt: string;
 30→};
 31→
 32→export type AgentStatusView =
 33→  | AgentStatusViewHidden
 34→  | AgentStatusViewAssign
 35→  | AgentStatusViewActive;
 36→
 37→export type DeriveAgentStatusInput = {
 38→  entityKind: string;
 39→  entityStatus: string;
 40→  agentSession?: AgentSessionSummary;
 41→};
 42→
 43→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 44→  if (input.entityKind !== "task") {
 45→    return { variant: "hidden" };
 46→  }
 47→
 48→  if (input.agentSession) {
 49→    return {
 50→      variant: "active",
 51→      agentSessionId: input.agentSession.agentSessionId,
 52→      orchestratorStatus: input.agentSession.orchestratorStatus,
 53→      filesChangedCount: input.agentSession.filesChangedCount,
 54→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 55→      startedAt: input.agentSession.startedAt,
 56→    };
 57→  }
 58→
 59→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 60→    return { variant: "assign" };
 61→  }
 62→
 63→  return { variant: "hidden" };
 64→}
 65→
 66→// ---------------------------------------------------------------------------
 67→// Status badge display
 68→// ---------------------------------------------------------------------------
 69→
 70→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 71→  spawning: "Spawning",
 72→  active: "Working",
 73→  idle: "Idle",
 74→  completed: "Completed",
 75→  aborted: "Aborted",
 76→  error: "Error",
 77→};
 78→
 79→function statusLabel(status: AgentSessionStatus): string {
 80→  return STATUS_LABELS[status];
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Component
 85→// ---------------------------------------------------------------------------
 86→
 87→export function AgentStatusSection({
 88→  entityId,
 89→  workspaceId,
 90→  entityKind,
 91→  entityStatus,
 92→  agentSession,
 93→}: {
 94→  entityId: string;
 95→  workspaceId: string;
 96→  entityKind: EntityKind;
 97→  entityStatus: string;
 98→  agentSession?: AgentSessionSummary;
 99→}) {
100→  const repoPath = useWorkspaceState((s) => s.repoPath);
101→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
102→  const [assigning, setAssigning] = useState(false);
103→  const [assignError, setAssignError] = useState<string | undefined>();
104→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
105→  const [repoPathInput, setRepoPathInput] = useState("");
106→  const [settingRepoPath, setSettingRepoPath] = useState(false);
107→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
108→
109→  // Derive the initial view from props
110→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
111→
112→  // If we have an assign result, use its stream URL; otherwise use session from props.
113→  // streamUrl is a dependency of useAgentSession's useEffect, so when assignResult
114→  // arrives and triggers a re-render, the hook will start the SSE subscription.
115→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
116→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
117→
118→  // SSE subscription -- only active when we have a stream URL
119→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
120→
121→  // Determine what to show
122→  const hasActiveStream = streamUrl !== undefined;
123→
124→  if (initialView.variant === "hidden" && !hasActiveStream) {
125→    return undefined;
126→  }
127→
128→  async function handleAssign() {
129→    if (assigning) return;
130→    setAssigning(true);
131→    setAssignError(undefined);
132→    try {
133→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
134→      const result = await assignAgent(workspaceId, rawTaskId);
135→      setAssignResult(result);
136→    } catch (err) {
137→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
138→    } finally {
139→      setAssigning(false);
140→    }
141→  }
142→
143→  // Show active session view (either from props or from fresh assignment)
144→  if (hasActiveStream) {
145→    const displayStatus = sessionState.status;
146→    const displayFiles = initialView.variant === "active"
147→      ? initialView.filesChangedCount + sessionState.filesChanged
148→      : sessionState.filesChanged;
149→
150→    const currentSessionId = assignResult?.agentSessionId
151→      ?? (initialView.variant === "active" ? initialView.agentSessionId : "");
152→
153→    return (
154→      <div className="entity-detail-section agent-status-section">
155→        <h4>Agent</h4>
156→        <div className="agent-status-row">
157→          <span className={`agent-status-badge agent-status-${displayStatus}`} data-testid="agent-status-badge">
158→            {statusLabel(displayStatus)}
159→          </span>
160→          {displayFiles > 0 ? (
161→            <span className="agent-file-count" data-testid="agent-file-count">
162→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
163→            </span>
164→          ) : undefined}
165→        </div>
166→        <AgentSessionPanel
167→          workspaceId={workspaceId}
168→          agentSessionId={currentSessionId}
169→          sessionStatus={displayStatus}
170→          outputEntries={sessionState.outputEntries}
171→          stallWarning={sessionState.stallWarning}
172→          connectionError={sessionState.connectionError}
173→        />
174→        {displayStatus === "idle" ? (
175→          <a
176→            className="agent-review-link"
177→            data-testid="agent-review-link"
178→            href={`/review/${encodeURIComponent(currentSessionId)}`}
179→          >
180→            Review
181→          </a>
182→        ) : undefined}
183→      </div>
184→    );
185→  }
186→
187→  // Show assign button (with missing repo_path banner when applicable)
188→  if (initialView.variant === "assign") {
189→    const missingRepoPath = repoPath === undefined;
190→
191→    return (
192→      <div className="entity-detail-section agent-status-section">
193→        <h4>Agent</h4>
194→        {missingRepoPath ? (
195→          <div className="agent-repo-path-banner" data-testid="agent-repo-path-banner">
196→            <p>Repository path is not configured for this workspace. Set it before assigning an agent.</p>
197→            <form
198→              className="agent-repo-path-form"
199→              data-testid="agent-repo-path-form"
200→              onSubmit={async (e) => {
201→                e.preventDefault();
202→                const trimmed = repoPathInput.trim();
203→                if (!trimmed || settingRepoPath) return;
204→                setSettingRepoPath(true);
205→                setRepoPathError(undefined);
206→                try {
207→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
208→                    method: "POST",
209→                    headers: { "Content-Type": "application/json" },
210→                    body: JSON.stringify({ path: trimmed }),
211→                  });
212→                  if (!res.ok) {
213→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
214→                    setRepoPathError(body.error ?? "Failed to set repository path");
215→                    return;
216→                  }
217→                  setStoreRepoPath(trimmed);
218→                  setRepoPathInput("");
219→                } catch {
220→                  setRepoPathError("Network error");
221→                } finally {
222→                  setSettingRepoPath(false);
223→                }
224→              }}
225→            >
226→              <input
227→                type="text"
228→                className="agent-repo-path-input"
229→                data-testid="agent-repo-path-input"
230→                placeholder="/path/to/git/repository"
231→                value={repoPathInput}
232→                onChange={(e) => setRepoPathInput(e.target.value)}
233→                disabled={settingRepoPath}
234→              />
235→              <button
236→                type="submit"
237→                className="agent-repo-path-action"
238→                data-testid="agent-repo-path-action"
239→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
240→              >
241→                {settingRepoPath ? "Setting..." : "Set Path"}
242→              </button>
243→            </form>
244→            {repoPathError ? (
245→              <p className="agent-repo-path-error" data-testid="agent-repo-path-error">{repoPathError}</p>
246→            ) : undefined}
247→          </div>
248→        ) : undefined}
249→        <button
250→          type="button"
251→          className="agent-assign-button"
252→          data-testid="agent-assign-button"
253→          disabled={assigning || missingRepoPath}
254→          onClick={handleAssign}
255→        >
256→          {assigning ? "Assigning..." : "Assign Agent"}
257→        </button>
258→        {assignError ? (
259→          <p className="agent-assign-error" data-testid="agent-assign-error">{assignError}</p>
260→        ) : undefined}
261→      </div>
262→    );
263→  }
264→
265→  return undefined;
266→}
