  1→/**
  2→ * useAgentSession -- SSE subscription hook for agent session state.
  3→ *
  4→ * Opens an EventSource when given an active sessionId + streamUrl.
  5→ * Exposes AgentSessionState: status, filesChanged, startedAt,
  6→ * stallWarning, connectionError.
  7→ *
  8→ * Pure core: reduceAgentSessionEvent handles all state transitions.
  9→ * Effect boundary: useEffect manages EventSource lifecycle + stall timer.
 10→ */
 11→
 12→import { useCallback, useEffect, useRef, useState } from "react";
 13→import type {
 14→  AgentStatusEvent,
 15→  AgentFileChangeEvent,
 16→  AgentStallWarningEvent,
 17→  AgentTokenEvent,
 18→  AgentPromptEvent,
 19→} from "../../shared/contracts";
 20→
 21→// ---------------------------------------------------------------------------
 22→// Types
 23→// ---------------------------------------------------------------------------
 24→
 25→export type AgentSessionStatus =
 26→  | "spawning"
 27→  | "active"
 28→  | "idle"
 29→  | "completed"
 30→  | "aborted"
 31→  | "error";
 32→
 33→export type OutputEntryToken = { kind: "token"; text: string };
 34→export type OutputEntryFileChange = {
 35→  kind: "file_change";
 36→  file: string;
 37→  changeType: "created" | "modified" | "deleted";
 38→};
 39→export type OutputEntryPrompt = { kind: "prompt"; text: string };
 40→
 41→export type OutputEntry =
 42→  | OutputEntryToken
 43→  | OutputEntryFileChange
 44→  | OutputEntryPrompt;
 45→
 46→export type AgentSessionState = {
 47→  status: AgentSessionStatus;
 48→  filesChanged: number;
 49→  startedAt: string;
 50→  lastEventAt?: string;
 51→  stallWarning?: { lastEventAt: string; stallDurationSeconds: number };
 52→  error?: string;
 53→  connectionError?: string;
 54→  outputEntries: OutputEntry[];
 55→};
 56→
 57→// Events the reducer handles (subset of StreamEvent relevant to agent sessions)
 58→type AgentEvent =
 59→  | AgentStatusEvent
 60→  | AgentFileChangeEvent
 61→  | AgentStallWarningEvent
 62→  | AgentTokenEvent
 63→  | AgentPromptEvent;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Constants
 67→// ---------------------------------------------------------------------------
 68→
 69→export const STALL_TIMEOUT_MS = 30_000;
 70→
 71→// ---------------------------------------------------------------------------
 72→// Pure core: state reducer
 73→// ---------------------------------------------------------------------------
 74→
 75→export function createInitialState(startedAt: string): AgentSessionState {
 76→  return {
 77→    status: "spawning",
 78→    filesChanged: 0,
 79→    startedAt,
 80→    outputEntries: [],
 81→  };
 82→}
 83→
 84→export function isTerminalStatus(status: AgentSessionStatus): boolean {
 85→  return status === "completed" || status === "aborted" || status === "error";
 86→}
 87→
 88→export function reduceAgentSessionEvent(
 89→  state: AgentSessionState,
 90→  event: AgentEvent,
 91→): AgentSessionState {
 92→  const now = new Date().toISOString();
 93→
 94→  switch (event.type) {
 95→    case "agent_status":
 96→      return {
 97→        ...state,
 98→        status: event.status,
 99→        lastEventAt: now,
100→        stallWarning: undefined,
101→        error: event.error,
102→      };
103→
104→    case "agent_file_change":
105→      return {
106→        ...state,
107→        filesChanged: state.filesChanged + 1,
108→        lastEventAt: now,
109→        stallWarning: undefined,
110→        outputEntries: [
111→          ...state.outputEntries,
112→          {
113→            kind: "file_change" as const,
114→            file: event.file,
115→            changeType: event.changeType,
116→          },
117→        ],
118→      };
119→
120→    case "agent_stall_warning":
121→      return {
122→        ...state,
123→        lastEventAt: now,
124→        stallWarning: {
125→          lastEventAt: event.lastEventAt,
126→          stallDurationSeconds: event.stallDurationSeconds,
127→        },
128→      };
129→
130→    case "agent_token":
131→      return {
132→        ...state,
133→        lastEventAt: now,
134→        stallWarning: undefined,
135→        outputEntries: [
136→          ...state.outputEntries,
137→          { kind: "token" as const, text: event.token },
138→        ],
139→      };
140→
141→    case "agent_prompt":
142→      return {
143→        ...state,
144→        lastEventAt: now,
145→        stallWarning: undefined,
146→        outputEntries: [
147→          { kind: "prompt" as const, text: event.text },
148→        ],
149→      };
150→  }
151→}
152→
153→// ---------------------------------------------------------------------------
154→// Hook return type
155→// ---------------------------------------------------------------------------
156→
157→export type UseAgentSessionReturn = {
158→  state: AgentSessionState;
159→  close: () => void;
160→};
161→
162→// ---------------------------------------------------------------------------
163→// Hook: effect boundary (EventSource lifecycle + stall timer)
164→// ---------------------------------------------------------------------------
165→
166→export function useAgentSession(
167→  streamUrl: string | undefined,
168→  startedAt: string,
169→): UseAgentSessionReturn {
170→  const [state, setState] = useState<AgentSessionState>(() =>
171→    createInitialState(startedAt),
172→  );
173→  const eventSourceRef = useRef<EventSource | undefined>(undefined);
174→  const stallTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
175→
176→  // Timer lifecycle: clearStallTimer is stable (no deps). resetStallTimer depends only on
177→  // clearStallTimer, so it is also stable. Both use stallTimerRef (a ref, not state) to avoid
178→  // stale closures. setState updater form ensures state reads are always current.
179→  const clearStallTimer = useCallback(() => {
180→    if (stallTimerRef.current !== undefined) {
181→      clearTimeout(stallTimerRef.current);
182→      stallTimerRef.current = undefined;
183→    }
184→  }, []);
185→
186→  const resetStallTimer = useCallback(() => {
187→    clearStallTimer();
188→    stallTimerRef.current = setTimeout(() => {
189→      setState((prev) => ({
190→        ...prev,
191→        stallWarning: {
192→          lastEventAt: prev.lastEventAt ?? prev.startedAt,
193→          stallDurationSeconds: STALL_TIMEOUT_MS / 1000,
194→        },
195→      }));
196→    }, STALL_TIMEOUT_MS);
197→  }, [clearStallTimer]);
198→
199→  useEffect(() => {
200→    if (!streamUrl) return;
201→
202→    const eventSource = new EventSource(streamUrl);
203→    eventSourceRef.current = eventSource;
204→
205→    function handleEvent(eventType: string, rawData: string) {
206→      try {
207→        const data = JSON.parse(rawData);
208→        const event: AgentEvent = { ...data, type: eventType };
209→        setState((prev) => reduceAgentSessionEvent(prev, event));
210→        resetStallTimer();
211→
212→        // Close on terminal status
213→        if (eventType === "agent_status" && isTerminalStatus(data.status)) {
214→          eventSource.close();
215→          clearStallTimer();
216→        }
217→      } catch {
218→        // Malformed event data -- ignore
219→      }
220→    }
221→
222→    eventSource.addEventListener("agent_status", (e) =>
223→      handleEvent("agent_status", e.data),
224→    );
225→    eventSource.addEventListener("agent_file_change", (e) =>
226→      handleEvent("agent_file_change", e.data),
227→    );
228→    eventSource.addEventListener("agent_stall_warning", (e) =>
229→      handleEvent("agent_stall_warning", e.data),
230→    );
231→    eventSource.addEventListener("agent_token", (e) =>
232→      handleEvent("agent_token", e.data),
233→    );
234→    eventSource.addEventListener("agent_prompt", (e) =>
235→      handleEvent("agent_prompt", e.data),
236→    );
237→
238→    eventSource.onerror = () => {
239→      eventSource.close();
240→      clearStallTimer();
241→      setState((prev) => ({
242→        ...prev,
243→        status: "error",
244→        connectionError: "Connection lost",
245→      }));
246→    };
247→
248→    // Start stall timer
249→    resetStallTimer();
250→
251→    return () => {
252→      eventSource.close();
253→      eventSourceRef.current = undefined;
254→      clearStallTimer();
255→    };
256→  }, [streamUrl, resetStallTimer, clearStallTimer]);
257→
258→  const close = useCallback(() => {
259→    if (eventSourceRef.current) {
260→      eventSourceRef.current.close();
261→      eventSourceRef.current = undefined;
262→    }
263→    clearStallTimer();
264→  }, [clearStallTimer]);
265→
266→  return { state, close };
267→}
