 20→// ---------------------------------------------------------------------------
 21→// Test helpers: async generators that simulate OpenCode event streams
 22→// ---------------------------------------------------------------------------
 23→
 24→function createOpencodeEventStream(
 25→  events: OpencodeEvent[],
 26→): AsyncIterable<unknown> {
 27→  return {
 28→    async *[Symbol.asyncIterator]() {
 29→      for (const event of events) {
 30→        yield event;
 31→      }
 32→    },
 33→  };
 34→}
 35→
 36→function createDelayedEventStream(
 37→  events: Array<{ event: OpencodeEvent; delayMs: number }>,
 38→): AsyncIterable<unknown> {
 39→  return {
 40→    async *[Symbol.asyncIterator]() {
 41→      for (const { event, delayMs } of events) {
 42→        await Bun.sleep(delayMs);
 43→        yield event;
 44→      }
 45→    },
 46→  };
 47→}
 48→
 49→function createErrorStream(
 50→  eventsBeforeError: OpencodeEvent[],
 51→  error: Error,
 52→): AsyncIterable<unknown> {
 53→  return {
 54→    async *[Symbol.asyncIterator]() {
 55→      for (const event of eventsBeforeError) {
 56→        yield event;
 57→      }
 58→      throw error;
 59→    },
 60→  };
 61→}
