 64→// Spy factory for EventIterationDeps
 65→// ---------------------------------------------------------------------------
 66→
 67→type DepsSpy = {
 68→  deps: EventIterationDeps;
 69→  emittedEvents: Array<{ streamId: string; event: unknown }>;
 70→  statusUpdates: Array<{ sessionId: string; status: OrchestratorStatus; error?: string }>;
 71→  lastEventAtCalls: string[];
 72→  stallDetectorStarted: boolean;
 73→  stallActivityCalls: number;
 74→  stallStepCalls: number;
 75→  stallStopped: boolean;
 76→};
 77→
 78→function createDepsSpy(options?: {
 79→  sessionStatus?: OrchestratorStatus;
 80→}): DepsSpy {
 81→  const spy: DepsSpy = {
 82→    deps: undefined as unknown as EventIterationDeps,
 83→    emittedEvents: [],
 84→    statusUpdates: [],
 85→    lastEventAtCalls: [],
 86→    stallDetectorStarted: false,
 87→    stallActivityCalls: 0,
 88→    stallStepCalls: 0,
 89→    stallStopped: false,
 90→  };
 91→
 92→  spy.deps = {
 93→    emitEvent: (streamId: string, event: unknown) => {
 94→      spy.emittedEvents.push({ streamId, event });
 95→    },
 96→    updateSessionStatus: async (
 97→      sessionId: string,
 98→      status: OrchestratorStatus,
 99→      error?: string,
100→    ) => {
101→      spy.statusUpdates.push({ sessionId, status, ...(error ? { error } : {}) });
102→    },
103→    updateLastEventAt: async (sessionId: string) => {
104→      spy.lastEventAtCalls.push(sessionId);
105→    },
106→    getSessionStatus: async (_sessionId: string) => {
107→      return options?.sessionStatus ?? "spawning";
108→    },
109→    startStallDetector: (_sessionId: string, _streamId: string) => ({
110→      recordActivity: () => { spy.stallActivityCalls++; },
111→      incrementStepCount: () => { spy.stallStepCalls++; },
112→      stop: () => { spy.stallStopped = true; },
113→    }),
114→  };
115→
116→  spy.stallDetectorStarted = false;
117→  const originalStart = spy.deps.startStallDetector;
118→  spy.deps.startStallDetector = (sessionId, streamId) => {
119→    spy.stallDetectorStarted = true;
120→    return originalStart(sessionId, streamId);
121→  };
122→
123→  return spy;
124→}
