  1→/**
  2→ * AgentSessionOutput -- renders accumulated agent output as streaming text
  3→ * with inline file change notifications.
  4→ *
  5→ * Pure presentational component. All state managed by useAgentSession hook.
  6→ * Auto-scrolls to latest content while streaming is active.
  7→ */
  8→
  9→import { useEffect, useRef } from "react";
 10→import type { OutputEntry } from "../../hooks/use-agent-session";
 11→import { isTerminalStatus, type AgentSessionStatus } from "../../hooks/use-agent-session";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Pure core: derive display text from output entries
 15→// ---------------------------------------------------------------------------
 16→
 17→export function renderTokenText(entries: OutputEntry[]): string {
 18→  return entries
 19→    .filter((e): e is Extract<OutputEntry, { kind: "token" }> => e.kind === "token")
 20→    .map((e) => e.text)
 21→    .join("");
 22→}
 23→
 24→// ---------------------------------------------------------------------------
 25→// Component
 26→// ---------------------------------------------------------------------------
 27→
 28→export function AgentSessionOutput({
 29→  outputEntries,
 30→  status,
 31→}: {
 32→  outputEntries: OutputEntry[];
 33→  status: AgentSessionStatus;
 34→}) {
 35→  const containerRef = useRef<HTMLDivElement>(null);
 36→  const isStreaming = !isTerminalStatus(status) && status !== "idle";
 37→
 38→  // Auto-scroll to bottom when new entries arrive during active streaming
 39→  useEffect(() => {
 40→    if (isStreaming && containerRef.current) {
 41→      containerRef.current.scrollTop = containerRef.current.scrollHeight;
 42→    }
 43→  }, [outputEntries.length, isStreaming]);
 44→
 45→  if (outputEntries.length === 0) {
 46→    return (
 47→      <div
 48→        className="agent-session-output agent-session-output--empty"
 49→        data-testid="agent-session-output"
 50→      >
 51→        <p className="agent-session-output__placeholder">
 52→          Waiting for agent output...
 53→        </p>
 54→      </div>
 55→    );
 56→  }
 57→
 58→  return (
 59→    <div
 60→      ref={containerRef}
 61→      className="agent-session-output"
 62→      data-testid="agent-session-output"
 63→    >
 64→      {outputEntries.map((entry, index) => {
 65→        switch (entry.kind) {
 66→          case "token":
 67→            return (
 68→              <span
 69→                key={index}
 70→                className="agent-session-output__token"
 71→                data-testid="agent-output-token"
 72→              >
 73→                {entry.text}
 74→              </span>
 75→            );
 76→          case "file_change":
 77→            return (
 78→              <div
 79→                key={index}
 80→                className="agent-session-output__file-change"
 81→                data-testid="agent-output-file-change"
 82→              >
 83→                <span className="agent-session-output__file-icon">
 84→                  {entry.changeType === "created"
 85→                    ? "+"
 86→                    : entry.changeType === "deleted"
 87→                      ? "-"
 88→                      : "~"}
 89→                </span>
 90→                <span className="agent-session-output__file-path">
 91→                  {entry.file}
 92→                </span>
 93→              </div>
 94→            );
 95→          case "prompt":
 96→            return (
 97→              <div
 98→                key={index}
 99→                className="agent-session-output__prompt"
100→                data-testid="agent-output-prompt"
101→              >
102→                {entry.text}
103→              </div>
104→            );
105→        }
106→      })}
107→    </div>
108→  );
109→}
