  1→/**
  2→ * AgentSessionPanel -- composite panel for active agent sessions.
  3→ *
  4→ * Renders agent output, follow-up prompt input, and abort button.
  5→ * Pure core: derivePromptInputView determines input state from session status.
  6→ * Effect boundary: the component wires sendPrompt and abortSession API calls.
  7→ */
  8→
  9→import { useState } from "react";
 10→import type { AgentSessionStatus, OutputEntry } from "../../hooks/use-agent-session";
 11→import { isTerminalStatus } from "../../hooks/use-agent-session";
 12→import { AgentSessionOutput } from "./AgentSessionOutput";
 13→import { sendPrompt, abortSession } from "../../graph/orchestrator-api";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Pure core: prompt input view derivation
 17→// ---------------------------------------------------------------------------
 18→
 19→const PROMPTABLE_STATUSES = new Set<AgentSessionStatus>(["active", "idle"]);
 20→
 21→export type PromptInputEnabled = { variant: "enabled" };
 22→export type PromptInputSubmitting = { variant: "submitting" };
 23→export type PromptInputDisabled = { variant: "disabled" };
 24→
 25→export type PromptInputView =
 26→  | PromptInputEnabled
 27→  | PromptInputSubmitting
 28→  | PromptInputDisabled;
 29→
 30→export type DerivePromptInputArgs = {
 31→  sessionStatus: AgentSessionStatus;
 32→  isSubmitting: boolean;
 33→};
 34→
 35→export function derivePromptInputView(args: DerivePromptInputArgs): PromptInputView {
 36→  if (!PROMPTABLE_STATUSES.has(args.sessionStatus)) {
 37→    return { variant: "disabled" };
 38→  }
 39→
 40→  if (args.isSubmitting) {
 41→    return { variant: "submitting" };
 42→  }
 43→
 44→  return { variant: "enabled" };
 45→}
 46→
 47→// ---------------------------------------------------------------------------
 48→// Component
 49→// ---------------------------------------------------------------------------
 50→
 51→export function AgentSessionPanel({
 52→  workspaceId,
 53→  agentSessionId,
 54→  sessionStatus,
 55→  outputEntries,
 56→  stallWarning,
 57→  connectionError,
 58→}: {
 59→  workspaceId: string;
 60→  agentSessionId: string;
 61→  sessionStatus: AgentSessionStatus;
 62→  outputEntries: OutputEntry[];
 63→  stallWarning?: { lastEventAt: string; stallDurationSeconds: number };
 64→  connectionError?: string;
 65→}) {
 66→  const [promptText, setPromptText] = useState("");
 67→  const [isSubmitting, setIsSubmitting] = useState(false);
 68→  const [promptError, setPromptError] = useState<string | undefined>();
 69→  const [isAborting, setIsAborting] = useState(false);
 70→
 71→  const inputView = derivePromptInputView({ sessionStatus, isSubmitting });
 72→  const inputDisabled = inputView.variant !== "enabled";
 73→  const showPromptInput = !isTerminalStatus(sessionStatus);
 74→
 75→  async function handleSubmitPrompt(e: React.FormEvent) {
 76→    e.preventDefault();
 77→    const trimmed = promptText.trim();
 78→    if (!trimmed || inputDisabled) return;
 79→
 80→    setIsSubmitting(true);
 81→    setPromptError(undefined);
 82→    try {
 83→      await sendPrompt(workspaceId, agentSessionId, trimmed);
 84→      setPromptText("");
 85→    } catch (err) {
 86→      setPromptError(err instanceof Error ? err.message : "Failed to send prompt");
 87→    } finally {
 88→      setIsSubmitting(false);
 89→    }
 90→  }
 91→
 92→  async function handleAbort() {
 93→    if (isAborting) return;
 94→    setIsAborting(true);
 95→    try {
 96→      await abortSession(workspaceId, agentSessionId);
 97→    } catch {
 98→      // Abort errors are non-critical -- session may already be terminal
 99→    } finally {
100→      setIsAborting(false);
101→    }
102→  }
103→
104→  return (
105→    <div className="agent-session-panel" data-testid="agent-session-panel">
106→      <AgentSessionOutput
107→        outputEntries={outputEntries}
108→        status={sessionStatus}
109→      />
110→
111→      {stallWarning ? (
112→        <p className="agent-stall-warning" data-testid="agent-stall-warning">
113→          Agent may be stalled (no activity for {stallWarning.stallDurationSeconds}s)
114→        </p>
115→      ) : undefined}
116→
117→      {connectionError ? (
118→        <p className="agent-connection-error">{connectionError}</p>
119→      ) : undefined}
120→
121→      {showPromptInput ? (
122→        <form
123→          className="agent-prompt-form"
124→          data-testid="agent-prompt-form"
125→          onSubmit={handleSubmitPrompt}
126→        >
127→          <input
128→            type="text"
129→            className="agent-prompt-input"
130→            data-testid="agent-prompt-input"
131→            placeholder="Send follow-up instruction..."
132→            value={promptText}
133→            onChange={(e) => setPromptText(e.target.value)}
134→            disabled={inputDisabled}
135→          />
136→          <button
137→            type="submit"
138→            className="agent-prompt-submit"
139→            data-testid="agent-prompt-submit"
140→            disabled={inputDisabled || promptText.trim().length === 0}
141→          >
142→            {inputView.variant === "submitting" ? "Sending..." : "Send"}
143→          </button>
144→          <button
145→            type="button"
146→            className="agent-abort-button"
147→            data-testid="agent-abort-button"
148→            disabled={isAborting || isTerminalStatus(sessionStatus)}
149→            onClick={handleAbort}
150→          >
151→            {isAborting ? "Aborting..." : "Abort"}
152→          </button>
153→        </form>
154→      ) : (
155→        <div className="agent-session-panel__terminal-actions">
156→          <button
157→            type="button"
158→            className="agent-abort-button"
159→            data-testid="agent-abort-button"
160→            disabled={true}
161→          >
162→            Abort
163→          </button>
164→        </div>
165→      )}
166→
167→      {promptError ? (
168→        <p className="agent-prompt-error" data-testid="agent-prompt-error">{promptError}</p>
169→      ) : undefined}
170→    </div>
171→  );
172→}
173→

  1→/**
  2→ * Typed fetch wrappers for orchestrator endpoints.
  3→ *
  4→ * Follows the same error-handling pattern as graph/actions.ts:
  5→ * throw on non-OK responses with status and message.
  6→ */
  7→
  8→// ---------------------------------------------------------------------------
  9→// Response Types
 10→// ---------------------------------------------------------------------------
 11→
 12→export type AssignAgentResponse = {
 13→  agentSessionId: string;
 14→  streamId: string;
 15→  streamUrl: string;
 16→};
 17→
 18→export type SessionStatusResponse = {
 19→  agentSessionId: string;
 20→  orchestratorStatus: string;
 21→  worktreeBranch?: string;
 22→  startedAt: string;
 23→  lastEventAt?: string;
 24→};
 25→
 26→export type SessionReviewResponse = {
 27→  agentSessionId: string;
 28→  taskId: string;
 29→  taskTitle: string;
 30→  summary?: string;
 31→  diff: {
 32→    files: Array<{
 33→      path: string;
 34→      status: "added" | "modified" | "deleted";
 35→      additions: number;
 36→      deletions: number;
 37→    }>;
 38→    rawDiff: string;
 39→    stats: {
 40→      filesChanged: number;
 41→      insertions: number;
 42→      deletions: number;
 43→    };
 44→  };
 45→  session: {
 46→    startedAt: string;
 47→    lastEventAt?: string;
 48→    decisionsCount: number;
 49→    questionsCount: number;
 50→    observationsCount: number;
 51→  };
 52→};
 53→
 54→export type AcceptSessionResponse = {
 55→  accepted: boolean;
 56→  taskStatus: string;
 57→};
 58→
 59→export type RejectSessionResponse = {
 60→  rejected: boolean;
 61→  continuing: boolean;
 62→};
 63→
 64→export type AbortSessionResponse = {
 65→  aborted: boolean;
 66→  taskStatus: string;
 67→};
 68→
 69→export type SendPromptResponse = {
 70→  delivered: boolean;
 71→};
 72→
 73→// ---------------------------------------------------------------------------
 74→// Internal Helpers
 75→// ---------------------------------------------------------------------------
 76→
 77→function buildOrchestratorUrl(workspaceId: string, ...segments: string[]): string {
 78→  const base = `/api/orchestrator/${encodeURIComponent(workspaceId)}`;
 79→  if (segments.length === 0) return base;
 80→  return `${base}/${segments.map(encodeURIComponent).join("/")}`;
 81→}
 82→
 83→async function orchestratorFetch<T>(url: string, init?: RequestInit): Promise<T> {
 84→  const response = await fetch(url, init);
 85→  if (!response.ok) {
 86→    const text = await response.text();
 87→    throw new Error(`Orchestrator request failed (${response.status}): ${text}`);
 88→  }
 89→  return (await response.json()) as T;
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// API Functions
 94→// ---------------------------------------------------------------------------
 95→
 96→export function assignAgent(
 97→  workspaceId: string,
 98→  taskId: string,
 99→): Promise<AssignAgentResponse> {
100→  return orchestratorFetch<AssignAgentResponse>(
101→    buildOrchestratorUrl(workspaceId, "assign"),
102→    {
103→      method: "POST",
104→      headers: { "Content-Type": "application/json" },
105→      body: JSON.stringify({ taskId }),
106→    },
107→  );
108→}
109→
110→export function getSessionStatus(
111→  workspaceId: string,
112→  sessionId: string,
113→): Promise<SessionStatusResponse> {
114→  return orchestratorFetch<SessionStatusResponse>(
115→    buildOrchestratorUrl(workspaceId, "sessions", sessionId),
116→  );
117→}
118→
119→export function getSessionReview(
120→  workspaceId: string,
121→  sessionId: string,
122→): Promise<SessionReviewResponse> {
123→  return orchestratorFetch<SessionReviewResponse>(
124→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "review"),
125→  );
126→}
127→
128→export function acceptSession(
129→  workspaceId: string,
130→  sessionId: string,
131→  summary?: string,
132→): Promise<AcceptSessionResponse> {
133→  return orchestratorFetch<AcceptSessionResponse>(
134→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "accept"),
135→    {
136→      method: "POST",
137→      headers: { "Content-Type": "application/json" },
138→      body: JSON.stringify(summary !== undefined ? { summary } : {}),
139→    },
140→  );
141→}
142→
143→export function rejectSession(
144→  workspaceId: string,
145→  sessionId: string,
146→  feedback: string,
147→): Promise<RejectSessionResponse> {
148→  return orchestratorFetch<RejectSessionResponse>(
149→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "reject"),
150→    {
151→      method: "POST",
152→      headers: { "Content-Type": "application/json" },
153→      body: JSON.stringify({ feedback }),
154→    },
155→  );
156→}
157→
158→export function abortSession(
159→  workspaceId: string,
160→  sessionId: string,
161→): Promise<AbortSessionResponse> {
162→  return orchestratorFetch<AbortSessionResponse>(
163→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "abort"),
164→    {
165→      method: "POST",
166→      headers: { "Content-Type": "application/json" },
167→    },
168→  );
169→}
170→
171→export function sendPrompt(
172→  workspaceId: string,
173→  sessionId: string,
174→  text: string,
175→): Promise<SendPromptResponse> {
176→  return orchestratorFetch<SendPromptResponse>(
177→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "prompt"),
178→    {
179→      method: "POST",
180→      headers: { "Content-Type": "application/json" },
181→      body: JSON.stringify({ text }),
182→    },
183→  );
184→}
