  1→/**
  2→ * Event Stream Wiring: unit tests for startEventIteration
  3→ *
  4→ * Step 01-02: Wire event stream into session lifecycle
  5→ *
  6→ * Verifies that OpenCode events flow through the event bridge,
  7→ * session transitions to active on first event, stall detector
  8→ * receives signals, and iteration stops on terminal status or error.
  9→ */
 10→import { describe, expect, test, beforeEach } from "bun:test";
 11→import {
 12→  startEventIteration,
 13→  clearHandleRegistry,
 14→  type EventIterationDeps,
 15→} from "../../../app/src/server/orchestrator/session-lifecycle";
 16→import type { OpencodeEvent } from "../../../app/src/server/orchestrator/event-bridge";
 17→import type { OrchestratorStatus } from "../../../app/src/server/orchestrator/types";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Test helpers: async generators that simulate OpenCode event streams
 21→// ---------------------------------------------------------------------------
 22→
 23→function createOpencodeEventStream(
 24→  events: OpencodeEvent[],
 25→): AsyncIterable<unknown> {
 26→  return {
 27→    async *[Symbol.asyncIterator]() {
 28→      for (const event of events) {
 29→        yield event;
 30→      }
 31→    },
 32→  };
 33→}
 34→
 35→function createDelayedEventStream(
 36→  events: Array<{ event: OpencodeEvent; delayMs: number }>,
 37→): AsyncIterable<unknown> {
 38→  return {
 39→    async *[Symbol.asyncIterator]() {
 40→      for (const { event, delayMs } of events) {
 41→        await Bun.sleep(delayMs);
 42→        yield event;
 43→      }
 44→    },
 45→  };
 46→}
 47→
 48→function createErrorStream(
 49→  eventsBeforeError: OpencodeEvent[],
 50→  error: Error,
 51→): AsyncIterable<unknown> {
 52→  return {
 53→    async *[Symbol.asyncIterator]() {
 54→      for (const event of eventsBeforeError) {
 55→        yield event;
 56→      }
 57→      throw error;
 58→    },
 59→  };
 60→}
 61→
 62→// ---------------------------------------------------------------------------
 63→// Spy factory for EventIterationDeps
 64→// ---------------------------------------------------------------------------
 65→
 66→type DepsSpy = {
 67→  deps: EventIterationDeps;
 68→  emittedEvents: Array<{ streamId: string; event: unknown }>;
 69→  statusUpdates: Array<{ sessionId: string; status: OrchestratorStatus; error?: string }>;
 70→  lastEventAtCalls: string[];
 71→  stallDetectorStarted: boolean;
