 75→    spawnFn: undefined as unknown as SpawnOpenCodeFn,
 76→    promptCalls: [],
 77→    abortCalls: 0,
 78→    events,
 79→  };
 80→
 81→  async function* generateEvents() {
 82→    for (const event of events) {
 83→      yield event;
 84→    }
 85→  }
 86→
 87→  capture.spawnFn = async (_config, _worktreePath, _taskId) => {
 88→    const handle: OpenCodeHandle = {
 89→      sessionId: "oc-sess-1",
