 91→        capture.promptCalls.push(text);
 92→      },
 93→      eventStream: generateEvents(),
 94→      abort: () => {
 95→        capture.abortCalls++;
 96→      },
 97→    };
 98→    capture.capturedHandle = handle;
 99→    return handle;
100→  };

