115→// ---------------------------------------------------------------------------
116→// Event iteration — port (dependencies as function signatures)
117→// ---------------------------------------------------------------------------
118→
119→export type EventIterationDeps = {
120→  emitEvent: (streamId: string, event: StreamEvent) => void;
121→  updateSessionStatus: (
122→    sessionId: string,
123→    status: OrchestratorStatus,
124→    error?: string,
125→  ) => Promise<void>;
126→  updateLastEventAt: (sessionId: string) => Promise<void>;
127→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
128→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
129→};
130→
131→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
132→  TERMINAL_ORCHESTRATOR_STATUSES,
133→);
134→
135→/**
136→ * Iterates the OpenCode event stream, forwarding events through the event
137→ * bridge. Transitions session to "active" on first event, starts stall
138→ * detection, and stops on terminal status or error.
139→ *
140→ * Returns a Promise that resolves when iteration ends (for testing).
141→ * In production, this is launched fire-and-forget.
142→ */
143→export function startEventIteration(
144→  deps: EventIterationDeps,
145→  eventStream: AsyncIterable<unknown>,
146→  streamId: string,
147→  sessionId: string,
148→): Promise<void> {
149→  const stallDetector = deps.startStallDetector(sessionId, streamId);
150→
151→  const bridge = startEventBridge(
152→    {
153→      emitEvent: deps.emitEvent,
154→      updateLastEventAt: deps.updateLastEventAt,
155→    },
156→    streamId,
157→    sessionId,
158→    stallDetector,
159→  );
160→
161→  let firstEventReceived = false;
162→
163→  async function iterate(): Promise<void> {
164→    try {
165→      for await (const rawEvent of eventStream) {
166→        // Check if session has reached terminal status
167→        const currentStatus = await deps.getSessionStatus(sessionId);
168→        if (TERMINAL_STATUSES.has(currentStatus)) {
169→          break;
170→        }
171→
172→        // Transition to active on first event
173→        if (!firstEventReceived) {
174→          firstEventReceived = true;
175→          await deps.updateSessionStatus(sessionId, "active");
176→        }
177→
178→        // Forward through event bridge (transform + emit + stall detection)
179→        bridge.handleEvent(rawEvent as OpencodeEvent);
180→      }
181→    } catch (err) {
182→      const errorMessage = err instanceof Error ? err.message : String(err);
183→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
184→    } finally {
185→      bridge.stop();
186→    }
187→  }
188→
189→  return iterate();
190→}
191→
192→// ---------------------------------------------------------------------------
193→// Pure helpers
194→// ---------------------------------------------------------------------------
195→
196→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
197→  const result: Record<string, unknown> = {};
198→  for (const [key, value] of Object.entries(obj)) {
199→    if (value !== undefined && value !== null) {
200→      result[key] = value;
201→    }
202→  }
203→  return result as Partial<T>;
204→}
205→
206→function sessionNotFound(sessionId: string): SessionError {
207→  return {
208→    code: "SESSION_NOT_FOUND",
209→    message: `Session not found: ${sessionId}`,
210→    httpStatus: 404,
211→  };
212→}
213→
214→function worktreeError(message: string): SessionError {
215→  return {
216→    code: "WORKTREE_ERROR",
217→    message,
218→    httpStatus: 500,
219→  };
220→}
221→
222→function fromAssignmentError(error: AssignmentError): SessionError {
223→  return {
224→    code: error.code as SessionErrorCode,
225→    message: error.message,
226→    httpStatus: error.httpStatus,
227→  };
228→}
