285→// ---------------------------------------------------------------------------
286→// createOrchestratorSession
287→// ---------------------------------------------------------------------------
288→
289→type CreateSessionInput = {
290→  surreal: Surreal;
291→  shellExec: ShellExec;
292→  brainBaseUrl: string;
293→  workspaceId: string;
294→  taskId: string;
295→  authToken: string;
296→  spawnOpenCode?: SpawnOpenCodeFn;
297→  validateAssignment: (
298→    surreal: Surreal,
299→    workspaceId: string,
300→    taskId: string,
301→  ) => Promise<AssignmentResult>;
302→  createAgentSession: (input: {
303→    surreal: Surreal;
304→    agent: string;
305→    workspaceRecord: RecordId<"workspace", string>;
306→    taskId?: string;
307→  }) => Promise<{ session_id: string }>;
308→};
309→
310→export async function createOrchestratorSession(
311→  input: CreateSessionInput,
312→): Promise<OrchestratorSessionResult> {
313→  // 1. Validate assignment eligibility
314→  const assignmentResult = await input.validateAssignment(
315→    input.surreal,
316→    input.workspaceId,
317→    input.taskId,
318→  );
319→
320→  if (!assignmentResult.ok) {
321→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
322→  }
323→
324→  const { validation } = assignmentResult;
325→  const taskSlug = slugFromTitle(validation.title);
326→  const repoRoot = validation.repoPath;
327→
328→  // 2. Create worktree
329→  const worktreeResult = await createWorktree(
330→    input.shellExec,
331→    repoRoot,
332→    taskSlug,
333→  );
334→
335→  if (!worktreeResult.ok) {
336→    return {
337→      ok: false,
338→      error: worktreeError(worktreeResult.error.message),
339→    };
340→  }
341→
342→  const { branchName, worktreePath } = worktreeResult.value;
343→
344→  // 3. Create agent_session record
345→  const { session_id: agentSessionId } = await input.createAgentSession({
346→    surreal: input.surreal,
347→    agent: "opencode",
348→    workspaceRecord: validation.workspaceRecord,
349→    taskId: input.taskId,
350→  });
351→
352→  const streamId = generateStreamId(agentSessionId);
353→
354→  // 4. Build config and spawn OpenCode
355→  const config = buildOpencodeConfig({
356→    brainBaseUrl: input.brainBaseUrl,
357→    workspaceId: input.workspaceId,
358→    authToken: input.authToken,
359→  });
360→
361→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
362→  let handle: OpenCodeHandle;
363→  try {
364→    handle = await spawnFn(config, worktreePath, input.taskId);
365→  } catch (err) {
366→    // Rollback: remove worktree and delete agent_session on spawn failure
367→    await removeWorktree(input.shellExec, repoRoot, branchName);
368→    const sessionRecord = new RecordId("agent_session", agentSessionId);
369→    await input.surreal.delete(sessionRecord);
370→    return {
371→      ok: false,
372→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
373→    };
374→  }
375→
376→  // 5. Register handle for later abort
377→  handleRegistry.set(agentSessionId, handle);
378→
379→  // 6. Update agent_session with orchestrator fields
380→  const sessionRecord = new RecordId("agent_session", agentSessionId);
381→  await input.surreal.update(sessionRecord).merge({
382→    orchestrator_status: "spawning" as OrchestratorStatus,
383→    worktree_branch: branchName,
384→    worktree_path: worktreePath,
385→    opencode_session_id: handle.sessionId,
386→    stream_id: streamId,
387→  });
388→
389→  return {
390→    ok: true,
391→    value: {
392→      agentSessionId,
393→      streamId,
394→      worktreeBranch: branchName,
395→    },
396→  };
397→}
398→
399→// Default spawn -- placeholder for production use
400→async function defaultSpawnOpenCode(
401→  _config: OpencodeConfig,
402→  _worktreePath: string,
403→  _taskId: string,
404→): Promise<OpenCodeHandle> {
405→  throw new Error(
406→    "spawnOpenCode not provided -- must be injected for production use",
407→  );
408→}
409→
410→// ---------------------------------------------------------------------------
411→// getOrchestratorSessionStatus
412→// ---------------------------------------------------------------------------
413→
414→type GetStatusInput = {
415→  surreal: Surreal;
416→  sessionId: string;
417→};
418→
419→export async function getOrchestratorSessionStatus(
420→  input: GetStatusInput,
421→): Promise<SessionStatusResult> {
422→  const lookup = await lookupSession(input.surreal, input.sessionId);
423→  if (!lookup.ok) {
424→    return { ok: false, error: lookup.error };
425→  }
426→  const { session } = lookup;
427→
428→  return {
429→    ok: true,
430→    value: {
431→      orchestratorStatus: lookup.status,
432→      ...pickDefined({
433→        worktreeBranch: session.worktree_branch,
434→        worktreePath: session.worktree_path,
435→        startedAt: session.started_at,
436→        lastEventAt: session.last_event_at,
437→        error: session.error,
438→      }),
439→    },
440→  };
441→}
442→
443→// ---------------------------------------------------------------------------
444→// abortOrchestratorSession
445→// ---------------------------------------------------------------------------
446→
447→type AbortSessionInput = {
448→  surreal: Surreal;
449→  shellExec: ShellExec;
450→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
451→  sessionId: string;
452→  endAgentSession: (input: {
453→    surreal: Surreal;
454→    workspaceRecord: RecordId<"workspace", string>;
455→    sessionId: string;
456→    summary: string;
457→  }) => Promise<{ session_id: string; ended: boolean }>;
458→};
459→
460→export async function abortOrchestratorSession(
461→  input: AbortSessionInput,
462→): Promise<AbortSessionResult> {
463→  const lookup = await lookupSession(input.surreal, input.sessionId);
464→  if (!lookup.ok) {
465→    return { ok: false, error: lookup.error };
466→  }
467→  const { session, record: sessionRecord } = lookup;
468→
469→  // 1. Kill the OpenCode process if handle exists
470→  const handle = handleRegistry.get(input.sessionId);
471→  if (handle) {
472→    handle.abort();
473→    handleRegistry.delete(input.sessionId);
474→  }
475→
476→  // 2. Update orchestrator_status to aborted
477→  await input.surreal.update(sessionRecord).merge({
478→    orchestrator_status: "aborted" as OrchestratorStatus,
479→  });
480→
481→  const workspaceRecord = requireWorkspace(session, input.sessionId);
482→
483→  // 3. Remove worktree if branch name exists
484→  if (session.worktree_branch) {
485→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
486→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
487→  }
488→
489→  // 4. Return task to ready
490→  if (session.task_id) {
491→    await input.surreal.update(session.task_id).merge({
492→      status: "ready",
493→      updated_at: new Date(),
494→    });
495→  }
496→
497→  // 5. End the agent session
498→  await input.endAgentSession({
499→    surreal: input.surreal,
500→    workspaceRecord,
501→    sessionId: input.sessionId,
502→    summary: "Session aborted",
503→  });
504→
505→  return {
506→    ok: true,
507→    value: {
508→      aborted: true,
509→      sessionId: input.sessionId,
510→    },
511→  };
512→}
513→
514→// ---------------------------------------------------------------------------
515→// acceptOrchestratorSession
516→// ---------------------------------------------------------------------------
517→
518→type AcceptSessionInput = {
519→  surreal: Surreal;
520→  sessionId: string;
521→  summary: string;
522→  endAgentSession: (input: {
523→    surreal: Surreal;
524→    workspaceRecord: RecordId<"workspace", string>;
525→    sessionId: string;
526→    summary: string;
527→  }) => Promise<{ session_id: string; ended: boolean }>;
528→};
529→
530→export async function acceptOrchestratorSession(
531→  input: AcceptSessionInput,
532→): Promise<AcceptSessionResult> {
533→  const lookup = await lookupSession(input.surreal, input.sessionId);
534→  if (!lookup.ok) {
535→    return { ok: false, error: lookup.error };
536→  }
537→  const { session, record: sessionRecord, status } = lookup;
538→
539→  if (!ACCEPTABLE_STATUSES.has(status)) {
540→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
541→  }
542→
543→  const workspaceRecord = requireWorkspace(session, input.sessionId);
544→
545→  // 1. Update orchestrator_status to completed
546→  await input.surreal.update(sessionRecord).merge({
547→    orchestrator_status: "completed" as OrchestratorStatus,
548→  });
549→
550→  // 2. Mark task as done
551→  if (session.task_id) {
552→    await input.surreal.update(session.task_id).merge({
553→      status: "done",
554→      updated_at: new Date(),
555→    });
556→  }
557→
558→  // 3. Clean up handle registry
559→  handleRegistry.delete(input.sessionId);
560→
561→  // 4. End the agent session
562→  await input.endAgentSession({
563→    surreal: input.surreal,
564→    workspaceRecord,
565→    sessionId: input.sessionId,
566→    summary: input.summary,
567→  });
568→
569→  return {
570→    ok: true,
571→    value: {
572→      accepted: true,
573→      sessionId: input.sessionId,
574→    },
575→  };
576→}
577→
578→// ---------------------------------------------------------------------------
579→// State guard helpers
580→// ---------------------------------------------------------------------------
581→
582→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
583→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
584→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
585→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
586→
587→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
588→  return {
589→    code: "SESSION_ERROR",
590→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
591→    httpStatus: 409,
592→  };
593→}
594→
595→function sessionAborted(sessionId: string): SessionError {
596→  return {
597→    code: "SESSION_ERROR",
598→    message: `Session ${sessionId} has been aborted`,
599→    httpStatus: 409,
600→  };
601→}
602→
603→// ---------------------------------------------------------------------------
604→// getOrchestratorReview
605→// ---------------------------------------------------------------------------
606→
607→type GetReviewInput = {
608→  surreal: Surreal;
609→  sessionId: string;
610→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
611→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
612→  getTaskTitle: (taskId: string) => Promise<string>;
613→};
614→
615→export async function getOrchestratorReview(
616→  input: GetReviewInput,
617→): Promise<ReviewResult> {
618→  const lookup = await lookupSession(input.surreal, input.sessionId);
619→  if (!lookup.ok) {
620→    return { ok: false, error: lookup.error };
621→  }
622→  const { session, status } = lookup;
623→
624→  if (status === "aborted") {
625→    return { ok: false, error: sessionAborted(input.sessionId) };
626→  }
627→
628→  if (!REVIEWABLE_STATUSES.has(status)) {
629→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
630→  }
631→
632→  // Get diff from the branch
633→  const branchName = session.worktree_branch ?? "";
634→  const workspaceRecord = requireWorkspace(session, input.sessionId);
635→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
636→  const diffResult = await input.getDiff(repoRoot, branchName);
637→
638→  const diff = diffResult.ok
639→    ? diffResult.value
640→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
641→
642→  // Get task title
643→  const taskId = session.task_id ? (session.task_id.id as string) : "";
644→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
645→
646→  return {
647→    ok: true,
648→    value: {
649→      taskTitle,
650→      diff,
651→      session: {
652→        orchestratorStatus: status,
653→        ...pickDefined({
654→          worktreeBranch: session.worktree_branch,
655→          startedAt: session.started_at,
656→          lastEventAt: session.last_event_at,
657→        }),
658→      },
659→    },
660→  };
661→}
662→
663→// ---------------------------------------------------------------------------
664→// rejectOrchestratorSession
665→// ---------------------------------------------------------------------------
666→
667→type RejectSessionInput = {
668→  surreal: Surreal;
669→  sessionId: string;
670→  feedback: string;
671→};
672→
673→export async function rejectOrchestratorSession(
674→  input: RejectSessionInput,
675→): Promise<RejectSessionResult> {
676→  const lookup = await lookupSession(input.surreal, input.sessionId);
677→  if (!lookup.ok) {
678→    return { ok: false, error: lookup.error };
679→  }
680→  const { session, record: sessionRecord, status } = lookup;
681→
682→  if (!REJECTABLE_STATUSES.has(status)) {
683→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
684→  }
685→
686→  // 1. Update session status to active (agent resumes work)
687→  await input.surreal.update(sessionRecord).merge({
688→    orchestrator_status: "active" as OrchestratorStatus,
689→    last_feedback: input.feedback,
690→  });
691→
692→  // 2. Return task to in_progress
693→  if (session.task_id) {
694→    await input.surreal.update(session.task_id).merge({
695→      status: "in_progress",
696→      updated_at: new Date(),
697→    });
698→  }
699→
700→  return {
701→    ok: true,
702→    value: {
703→      rejected: true,
704→      continuing: true,
705→    },
706→  };
707→}
708→
709→// ---------------------------------------------------------------------------
710→// sendSessionPrompt
711→// ---------------------------------------------------------------------------
712→
713→type SendPromptInput = {
714→  surreal: Surreal;
715→  sessionId: string;
716→  text: string;
717→};
718→
719→export async function sendSessionPrompt(
720→  input: SendPromptInput,
721→): Promise<PromptSessionResult> {
722→  const lookup = await lookupSession(input.surreal, input.sessionId);
723→  if (!lookup.ok) {
724→    return { ok: false, error: lookup.error };
725→  }
726→  const { status } = lookup;
727→
728→  if (!PROMPTABLE_STATUSES.has(status)) {
729→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
730→  }
731→
732→  const handle = handleRegistry.get(input.sessionId);
733→  if (!handle) {
734→    return {
735→      ok: false,
736→      error: {
737→        code: "SESSION_ERROR",
738→        message: `Cannot prompt session ${input.sessionId}: agent handle not available (server may have restarted)`,
739→        httpStatus: 409,
740→      },
741→    };
742→  }
743→
744→  // Fire-and-forget: deliver prompt to the agent process
745→  handle.sendPrompt(input.text).catch(() => {
746→    // Prompt delivery failure is non-fatal; the session continues
747→  });
748→
749→  return {
750→    ok: true,
751→    value: { delivered: true },
752→  };
753→}
754→

  1→/**
  2→ * AgentSessionPanel -- composite panel for active agent sessions.
  3→ *
  4→ * Renders agent output, follow-up prompt input, and abort button.
  5→ * Pure core: derivePromptInputView determines input state from session status.
  6→ * Effect boundary: the component wires sendPrompt and abortSession API calls.
  7→ */
  8→
  9→import { useState } from "react";
 10→import type { AgentSessionStatus, OutputEntry } from "../../hooks/use-agent-session";
 11→import { isTerminalStatus } from "../../hooks/use-agent-session";
 12→import { AgentSessionOutput } from "./AgentSessionOutput";
 13→import { sendPrompt, abortSession } from "../../graph/orchestrator-api";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Pure core: prompt input view derivation
 17→// ---------------------------------------------------------------------------
 18→
 19→const PROMPTABLE_STATUSES = new Set<AgentSessionStatus>(["active", "idle"]);
 20→
 21→export type PromptInputEnabled = { variant: "enabled" };
 22→export type PromptInputSubmitting = { variant: "submitting" };
 23→export type PromptInputDisabled = { variant: "disabled" };
 24→
 25→export type PromptInputView =
 26→  | PromptInputEnabled
 27→  | PromptInputSubmitting
 28→  | PromptInputDisabled;
 29→
 30→export type DerivePromptInputArgs = {
 31→  sessionStatus: AgentSessionStatus;
 32→  isSubmitting: boolean;
 33→};
 34→
 35→export function derivePromptInputView(args: DerivePromptInputArgs): PromptInputView {
 36→  if (!PROMPTABLE_STATUSES.has(args.sessionStatus)) {
 37→    return { variant: "disabled" };
 38→  }
 39→
 40→  if (args.isSubmitting) {
 41→    return { variant: "submitting" };
 42→  }
 43→
 44→  return { variant: "enabled" };
 45→}
 46→
 47→// ---------------------------------------------------------------------------
 48→// Component
 49→// ---------------------------------------------------------------------------
 50→
 51→export function AgentSessionPanel({
 52→  workspaceId,
 53→  agentSessionId,
 54→  sessionStatus,
 55→  outputEntries,
 56→  stallWarning,
 57→  connectionError,
 58→}: {
 59→  workspaceId: string;
 60→  agentSessionId: string;
 61→  sessionStatus: AgentSessionStatus;
 62→  outputEntries: OutputEntry[];
 63→  stallWarning?: { lastEventAt: string; stallDurationSeconds: number };
 64→  connectionError?: string;
 65→}) {
 66→  const [promptText, setPromptText] = useState("");
 67→  const [isSubmitting, setIsSubmitting] = useState(false);
 68→  const [promptError, setPromptError] = useState<string | undefined>();
 69→  const [isAborting, setIsAborting] = useState(false);
 70→
 71→  const inputView = derivePromptInputView({ sessionStatus, isSubmitting });
 72→  const inputDisabled = inputView.variant !== "enabled";
 73→  const showPromptInput = !isTerminalStatus(sessionStatus);
 74→
 75→  async function handleSubmitPrompt(e: React.FormEvent) {
 76→    e.preventDefault();
 77→    const trimmed = promptText.trim();
 78→    if (!trimmed || inputDisabled) return;
 79→
 80→    setIsSubmitting(true);
 81→    setPromptError(undefined);
 82→    try {
 83→      await sendPrompt(workspaceId, agentSessionId, trimmed);
 84→      setPromptText("");
 85→    } catch (err) {
 86→      setPromptError(err instanceof Error ? err.message : "Failed to send prompt");
 87→    } finally {
 88→      setIsSubmitting(false);
 89→    }
 90→  }
 91→
 92→  async function handleAbort() {
 93→    if (isAborting) return;
 94→    setIsAborting(true);
 95→    try {
 96→      await abortSession(workspaceId, agentSessionId);
 97→    } catch {
 98→      // Abort errors are non-critical -- session may already be terminal
 99→    } finally {
100→      setIsAborting(false);
101→    }
102→  }
103→
104→  return (
105→    <div className="agent-session-panel" data-testid="agent-session-panel">
106→      <AgentSessionOutput
107→        outputEntries={outputEntries}
108→        status={sessionStatus}
109→      />
110→
111→      {stallWarning ? (
112→        <p className="agent-stall-warning" data-testid="agent-stall-warning">
113→          Agent may be stalled (no activity for {stallWarning.stallDurationSeconds}s)
114→        </p>
115→      ) : undefined}
116→
117→      {connectionError ? (
118→        <p className="agent-connection-error">{connectionError}</p>
119→      ) : undefined}
120→
121→      {showPromptInput ? (
122→        <form
123→          className="agent-prompt-form"
124→          data-testid="agent-prompt-form"
125→          onSubmit={handleSubmitPrompt}
126→        >
127→          <input
128→            type="text"
129→            className="agent-prompt-input"
130→            data-testid="agent-prompt-input"
131→            placeholder="Send follow-up instruction..."
132→            value={promptText}
133→            onChange={(e) => setPromptText(e.target.value)}
134→            disabled={inputDisabled}
135→          />
136→          <button
137→            type="submit"
138→            className="agent-prompt-submit"
139→            data-testid="agent-prompt-submit"
140→            disabled={inputDisabled || promptText.trim().length === 0}
141→          >
142→            {inputView.variant === "submitting" ? "Sending..." : "Send"}
143→          </button>
144→          <button
145→            type="button"
146→            className="agent-abort-button"
147→            data-testid="agent-abort-button"
148→            disabled={isAborting || isTerminalStatus(sessionStatus)}
