  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined && value !== null) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
260→
261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const streamId = request.params.streamId;
272→
273→    if (!streamId) {
274→      return jsonError("streamId is required", 400);
275→    }
276→
277→    return deps.sseRegistry.handleStreamRequest(streamId);
278→  };
279→
280→  return { stream };
281→}
282→
283→// ---------------------------------------------------------------------------
284→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
285→// ---------------------------------------------------------------------------
286→
287→export type OrchestratorWiringDeps = {
288→  surreal: import("surrealdb").Surreal;
289→  shellExec: import("./worktree-manager").ShellExec;
290→  brainBaseUrl: string;
291→  sseRegistry?: SseRegistry;
292→};
293→
294→export function wireOrchestratorRoutes(
295→  wiringDeps: OrchestratorWiringDeps,
296→): {
297→  assign: RouteHandler;
298→  status: RouteHandler;
299→  accept: RouteHandler;
300→  abort: RouteHandler;
301→  review: RouteHandler;
302→  reject: RouteHandler;
303→  prompt: RouteHandler;
304→  stream?: RouteHandler;
305→} {
306→  // Lazy imports to keep module boundary clean
307→  const lifecycleImport = import("./session-lifecycle");
308→  const queriesImport = import("../mcp/mcp-queries");
309→  const guardImport = import("./assignment-guard");
310→
311→  // Helper: resolve repo_path from workspace record
312→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
313→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
314→      `SELECT repo_path FROM $ws;`,
315→      { ws: workspaceRecord },
316→    );
317→    const repoPath = rows[0]?.repo_path;
318→    if (!repoPath) {
319→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
320→    }
321→    return repoPath;
322→  };
323→
324→  // Use mock spawn for acceptance tests, production spawn otherwise
325→  const spawnOpenCodeImport = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true"
326→    ? Promise.resolve({
327→        spawnOpenCode: async () => ({
328→          sessionId: crypto.randomUUID(),
329→          abort: () => {},
330→          sendPrompt: async () => {},
331→          eventStream: (async function* () {})(),
332→        }),
333→      })
334→    : import("./spawn-opencode");
335→
336→  const routeDeps: OrchestratorRouteDeps = {
337→    createSession: async (workspaceId, taskId, authToken) => {
338→      const [lifecycle, queries, guard, { spawnOpenCode }] = await Promise.all([
339→        lifecycleImport,
340→        queriesImport,
341→        guardImport,
342→        spawnOpenCodeImport,
343→      ]);
344→      return lifecycle.createOrchestratorSession({
345→        surreal: wiringDeps.surreal,
346→        shellExec: wiringDeps.shellExec,
347→        brainBaseUrl: wiringDeps.brainBaseUrl,
348→        workspaceId,
349→        taskId,
350→        authToken,
351→        validateAssignment: guard.validateAssignment,
352→        createAgentSession: queries.createAgentSession,
353→        spawnOpenCode,
354→      });
355→    },
356→
357→    getSessionStatus: async (sessionId) => {
358→      const lifecycle = await lifecycleImport;
359→      return lifecycle.getOrchestratorSessionStatus({
360→        surreal: wiringDeps.surreal,
361→        sessionId,
362→      });
363→    },
364→
365→    abortSession: async (sessionId) => {
366→      const [lifecycle, queries] = await Promise.all([
367→        lifecycleImport,
368→        queriesImport,
369→      ]);
370→      return lifecycle.abortOrchestratorSession({
371→        surreal: wiringDeps.surreal,
372→        shellExec: wiringDeps.shellExec,
373→        resolveRepoRoot,
374→        sessionId,
375→        endAgentSession: queries.endAgentSession,
376→      });
377→    },
378→
379→    acceptSession: async (sessionId, summary) => {
380→      const [lifecycle, queries] = await Promise.all([
381→        lifecycleImport,
382→        queriesImport,
383→      ]);
384→      return lifecycle.acceptOrchestratorSession({
385→        surreal: wiringDeps.surreal,
386→        sessionId,
387→        summary,
388→        endAgentSession: queries.endAgentSession,
389→      });
390→    },
391→
392→    getReview: async (sessionId) => {
393→      const [lifecycle, worktreeManager] = await Promise.all([
394→        lifecycleImport,
395→        import("./worktree-manager"),
396→      ]);
397→      return lifecycle.getOrchestratorReview({
398→        surreal: wiringDeps.surreal,
399→        sessionId,
400→        resolveRepoRoot,
401→        getDiff: (repoRoot: string, branchName: string) =>
402→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
403→        getTaskTitle: async (taskId: string) => {
404→          const { RecordId } = await import("surrealdb");
405→          const taskRecord = new RecordId("task", taskId);
406→          const rows = (await wiringDeps.surreal.query(
407→            `SELECT title FROM $task;`,
408→            { task: taskRecord },
409→          )) as Array<Array<{ title: string }>>;
410→          return rows[0]?.[0]?.title ?? "";
411→        },
412→      });
413→    },
414→
415→    rejectSession: async (sessionId, feedback) => {
416→      const lifecycle = await lifecycleImport;
417→      return lifecycle.rejectOrchestratorSession({
418→        surreal: wiringDeps.surreal,
419→        sessionId,
420→        feedback,
421→      });
422→    },
423→
424→    sendPrompt: async (sessionId, text) => {
425→      const lifecycle = await lifecycleImport;
426→      return lifecycle.sendSessionPrompt({
427→        surreal: wiringDeps.surreal,
428→        sessionId,
429→        text,
430→      });
431→    },
432→  };
433→
434→  const handlers = createOrchestratorRouteHandlers(routeDeps);
435→
436→  const streamHandler = wiringDeps.sseRegistry
437→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
438→    : undefined;
439→
440→  return {
441→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
442→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
443→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
444→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
445→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
446→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
447→    prompt: withRequestLogging("orchestrator.prompt", "POST", handlers.prompt),
448→    ...(streamHandler
449→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
450→      : {}),
451→  };
452→}
