  3→/**
  4→ * Tests for useAgentReview hook logic.
  5→ *
  6→ * Since bun tests have no React renderer, we test the hook's core logic
  7→ * through its pure state-machine functions and verify it composes the
  8→ * orchestrator-api functions correctly.
  9→ *
 10→ * Behaviors under test:
 11→ *   1. fetchReview: fetches review data, tracks loading/error
 12→ *   2. accept: calls acceptSession, tracks pending/success/error
 13→ *   3. reject: calls rejectSession with feedback, tracks pending/success/error
 14→ */
 15→
 16→import {
 17→  reduceReviewAction,
 18→  createInitialReviewState,
 19→  type ReviewState,
 20→  type ReviewAction,
 21→} from "../../../../app/src/client/hooks/use-agent-review";
 22→
 23→// ---------------------------------------------------------------------------
 24→// Helpers
 25→// ---------------------------------------------------------------------------
 26→
 27→function applyActions(initial: ReviewState, actions: ReviewAction[]): ReviewState {
 28→  let state = initial;
 29→  for (const action of actions) {
 30→    state = reduceReviewAction(state, action);
 31→  }
 32→  return state;
 33→}
 34→
 35→// ---------------------------------------------------------------------------
 36→// Acceptance: full lifecycle
 37→// ---------------------------------------------------------------------------
 38→
 39→describe("useAgentReview state machine", () => {
 40→  describe("fetch review data lifecycle", () => {
 41→    it("transitions from idle to loading to loaded with review data", () => {
 42→      const reviewData = {
 43→        agentSessionId: "s-1",
 44→        taskId: "t-1",
 45→        taskTitle: "Fix login bug",
 46→        diff: {
 47→          files: [{ path: "src/auth.ts", status: "modified" as const, additions: 10, deletions: 2 }],
 48→          rawDiff: "diff --git ...",
 49→          stats: { filesChanged: 1, insertions: 10, deletions: 2 },
 50→        },
 51→        session: {
 52→          startedAt: "2026-03-07T12:00:00Z",
 53→          decisionsCount: 1,
 54→          questionsCount: 0,
 55→          observationsCount: 2,
 56→        },
 57→      };
 58→
 59→      const state = applyActions(createInitialReviewState(), [
 60→        { type: "FETCH_START" },
 61→        { type: "FETCH_SUCCESS", data: reviewData },
 62→      ]);
 63→
 64→      expect(state.fetchStatus).toBe("success");
 65→      expect(state.reviewData).toEqual(reviewData);
 66→      expect(state.fetchError).toBeUndefined();
 67→    });
 68→
 69→    it("transitions from idle to loading to error on fetch failure", () => {
 70→      const state = applyActions(createInitialReviewState(), [
 71→        { type: "FETCH_START" },
 72→        { type: "FETCH_ERROR", error: "Review not available" },
 73→      ]);
 74→
 75→      expect(state.fetchStatus).toBe("error");
 76→      expect(state.reviewData).toBeUndefined();
 77→      expect(state.fetchError).toBe("Review not available");
 78→    });
 79→  });
 80→
 81→  describe("accept mutation lifecycle", () => {
 82→    it("transitions through pending to success", () => {
 83→      const state = applyActions(createInitialReviewState(), [
 84→        { type: "ACCEPT_START" },
 85→        { type: "ACCEPT_SUCCESS" },
 86→      ]);
 87→
 88→      expect(state.acceptStatus).toBe("success");
 89→      expect(state.acceptError).toBeUndefined();
 90→    });
 91→
 92→    it("transitions through pending to error", () => {
 93→      const state = applyActions(createInitialReviewState(), [
 94→        { type: "ACCEPT_START" },
 95→        { type: "ACCEPT_ERROR", error: "Session not idle" },
 96→      ]);
 97→
 98→      expect(state.acceptStatus).toBe("error");
 99→      expect(state.acceptError).toBe("Session not idle");
100→    });
101→
102→    it("exposes loading state during pending", () => {
103→      const state = applyActions(createInitialReviewState(), [
104→        { type: "ACCEPT_START" },
105→      ]);
106→
107→      expect(state.acceptStatus).toBe("pending");
108→    });
109→  });
110→
111→  describe("reject mutation lifecycle", () => {
112→    it("transitions through pending to success", () => {
113→      const state = applyActions(createInitialReviewState(), [
114→        { type: "REJECT_START" },
115→        { type: "REJECT_SUCCESS" },
116→      ]);
117→
118→      expect(state.rejectStatus).toBe("success");
119→      expect(state.rejectError).toBeUndefined();
120→    });
121→
122→    it("transitions through pending to error", () => {
123→      const state = applyActions(createInitialReviewState(), [
124→        { type: "REJECT_START" },
125→        { type: "REJECT_ERROR", error: "Cannot reject completed session" },
126→      ]);
127→
128→      expect(state.rejectStatus).toBe("error");
129→      expect(state.rejectError).toBe("Cannot reject completed session");
130→    });
131→
132→    it("exposes loading state during pending", () => {
133→      const state = applyActions(createInitialReviewState(), [
134→        { type: "REJECT_START" },
135→      ]);
136→
137→      expect(state.rejectStatus).toBe("pending");
138→    });
139→  });
140→
141→  describe("initial state", () => {
142→    it("starts with idle status for all operations", () => {
143→      const state = createInitialReviewState();
144→
145→      expect(state.fetchStatus).toBe("idle");
146→      expect(state.acceptStatus).toBe("idle");
147→      expect(state.rejectStatus).toBe("idle");
148→      expect(state.reviewData).toBeUndefined();
149→      expect(state.fetchError).toBeUndefined();
150→      expect(state.acceptError).toBeUndefined();
151→      expect(state.rejectError).toBeUndefined();
152→    });
153→  });
154→});
